import pandas as pd
import numpy as np

class Alpha:
    pass

    @staticmethod
    def alpha_quanta_randomizer_001_rank(df, window=65):
        # Công thức: POW(REGBETA(close, SEQUENCE, window), 2) * TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        # Tính slope tương đương (REGBETA) giữa close và days
        days = pd.Series(np.arange(len(df)), index=df.index)
        days_rolling_mean = days.rolling(window).mean()
        close_rolling_mean = df['close'].rolling(window).mean()
        cov = (days - days_rolling_mean) * (df['close'] - close_rolling_mean)
        var_x = (days - days_rolling_mean) ** 2
        slope = cov.rolling(window).sum() / var_x.rolling(window).sum().replace(0, np.nan)
        # Square slope
        raw = slope ** 2
        # TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        var_sequence = days.rolling(window).var()
        var_close = df['close'].rolling(window).var() + 1e-8
        raw = raw * var_sequence / var_close
        # Chuẩn hóa Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_001_tanh(df, window=65):
        # Công thức: POW(REGBETA(close, SEQUENCE, window), 2) * TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        # Tính slope tương đương (REGBETA) giữa close và days
        days = pd.Series(np.arange(len(df)), index=df.index)
        days_rolling_mean = days.rolling(window).mean()
        close_rolling_mean = df['close'].rolling(window).mean()
        cov = (days - days_rolling_mean) * (df['close'] - close_rolling_mean)
        var_x = (days - days_rolling_mean) ** 2
        slope = cov.rolling(window).sum() / var_x.rolling(window).sum().replace(0, np.nan)
        # Square slope
        raw = slope ** 2
        # TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        var_sequence = days.rolling(window).var()
        var_close = df['close'].rolling(window).var() + 1e-8
        raw = raw * var_sequence / var_close
        # Chuẩn hóa Dynamic Tanh
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        signal = np.tanh(raw / std_raw)
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_001_zscore(df, window=55):
        # Công thức: POW(REGBETA(close, SEQUENCE, window), 2) * TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        # Tính slope tương đương (REGBETA) giữa close và days
        days = pd.Series(np.arange(len(df)), index=df.index)
        days_rolling_mean = days.rolling(window).mean()
        close_rolling_mean = df['close'].rolling(window).mean()
        cov = (days - days_rolling_mean) * (df['close'] - close_rolling_mean)
        var_x = (days - days_rolling_mean) ** 2
        slope = cov.rolling(window).sum() / var_x.rolling(window).sum().replace(0, np.nan)
        # Square slope
        raw = slope ** 2
        # TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        var_sequence = days.rolling(window).var()
        var_close = df['close'].rolling(window).var() + 1e-8
        raw = raw * var_sequence / var_close
        # Chuẩn hóa Rolling Z-Score / Clip
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std().replace(0, np.nan)
        signal = ((raw - mean_raw) / std_raw).clip(-1, 1)
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_001_sign(df, window=70):
        # Công thức: POW(REGBETA(close, SEQUENCE, window), 2) * TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        # Tính slope tương đương (REGBETA) giữa close và days
        days = pd.Series(np.arange(len(df)), index=df.index)
        days_rolling_mean = days.rolling(window).mean()
        close_rolling_mean = df['close'].rolling(window).mean()
        cov = (days - days_rolling_mean) * (df['close'] - close_rolling_mean)
        var_x = (days - days_rolling_mean) ** 2
        slope = cov.rolling(window).sum() / var_x.rolling(window).sum().replace(0, np.nan)
        # Square slope
        raw = slope ** 2
        # TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        var_sequence = days.rolling(window).var()
        var_close = df['close'].rolling(window).var() + 1e-8
        raw = raw * var_sequence / var_close
        # Chuẩn hóa Sign/Binary Soft
        signal = pd.Series(np.sign(raw), index=df.index).fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_001_wf(df, window=70, p1=0.9):
        # Công thức: POW(REGBETA(close, SEQUENCE, window), 2) * TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        # Tính slope tương đương (REGBETA) giữa close và days
        days = pd.Series(np.arange(len(df)), index=df.index)
        days_rolling_mean = days.rolling(window).mean()
        close_rolling_mean = df['close'].rolling(window).mean()
        cov = (days - days_rolling_mean) * (df['close'] - close_rolling_mean)
        var_x = (days - days_rolling_mean) ** 2
        slope = cov.rolling(window).sum() / var_x.rolling(window).sum().replace(0, np.nan)
        # Square slope
        raw = slope ** 2
        # TS_VAR(SEQUENCE, window) / (TS_VAR(close, window) + 1e-8)
        var_sequence = days.rolling(window).var()
        var_close = df['close'].rolling(window).var() + 1e-8
        raw = raw * var_sequence / var_close
        # Chuẩn hóa Winsorized Fisher
        low = raw.rolling(window).quantile(p1)
        high = raw.rolling(window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_002_rank(df, window=10):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.diff() / (close.shift(1) + 1e-8)
        vol_chg = volume.diff() / (volume.shift(1) + 1e-8)
        raw = ret.rolling(window).corr(vol_chg)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

