    @staticmethod
    def alpha_quanta_randomizer_003_k(df, window=50):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = close.pct_change().fillna(0)
        raw = ret.rolling(window).std() * volume.rolling(window).mean() / (volume.rolling(window).mean() + volume.rolling(window).std() + 1e-8)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

