    @staticmethod
    def alpha_quanta_randomizer_004_wf(df, window=30, p1=0.3):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_close = close.diff(1)
        delta_volume = volume.diff(1)
        ret = delta_close / close
        vol_ret = delta_volume / volume
        corr = ret.rolling(window).corr(vol_ret)
        raw = corr.fillna(0)
        low = raw.rolling(window*2).quantile(p1)
        high = raw.rolling(window*2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_005_rank(df, window=30):
        raw = df['high'] - df['low']
        vol_mean = raw.rolling(window).mean()
        hl_rel = raw / (vol_mean + 1e-8)
        vol_std = hl_rel.rolling(window).std()
        result = hl_rel * vol_std
        normalized = (result.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_005_tanh(df, window=80):
        raw = df['high'] - df['low']
        vol_mean = raw.rolling(window).mean()
        hl_rel = raw / (vol_mean + 1e-8)
        vol_std = hl_rel.rolling(window).std()
        result = hl_rel * vol_std
        normalized = np.tanh(result / (result.rolling(window).std() + 1e-8))
        return -normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_005_zscore(df, window=50):
        raw = df['high'] - df['low']
        vol_mean = raw.rolling(window).mean()
        hl_rel = raw / (vol_mean + 1e-8)
        vol_std = hl_rel.rolling(window).std()
        result = hl_rel * vol_std
        mean_res = result.rolling(window).mean()
        std_res = result.rolling(window).std()
        normalized = ((result - mean_res) / (std_res + 1e-8)).clip(-1, 1)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_005_sign(df, window=60):
        raw = df['high'] - df['low']
