    @staticmethod
    def alpha_quanta_randomizer_005_wf(df, window=30, p1=0.9):
        raw = df['high'] - df['low']
        vol_mean = raw.rolling(window).mean()
        hl_rel = raw / (vol_mean + 1e-8)
        vol_std = hl_rel.rolling(window).std()
        result = hl_rel * vol_std
        low = result.rolling(window).quantile(p1)
        high = result.rolling(window).quantile(1 - p1)
        winsorized = result.clip(lower=low, upper=high, axis=0)
        denominator = (high - low).replace(0, np.nan).fillna(method='ffill').fillna(1e-8)
        normalized = np.arctanh(((winsorized - low) / (denominator + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_006_rank(df, window=65):
        vol = df['matchingVolume']
        sq_vol = vol.rolling(window).kurt()
        ratio = vol / vol.rolling(window).mean()
        raw = sq_vol * ratio.rolling(window).mean()
        raw = raw.rolling(window).rank(pct=True) * 2 - 1
        return raw.fillna(0)

