        raw = beta ** 2 / (close.rolling(window).std() * volume.rolling(window).mean() + 1e-8)
        raw = raw.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        low = raw.rolling(window).quantile(p1)
