    @staticmethod
    def alpha_quanta_randomizer_011_k(df, window=50):
        _close = df['close']
        _open = df['open']
        volume = df.get('matchingVolume', df.get('volume', 1))
        delay_open = _open.shift(1)
        close_minus_delay = (_close - delay_open) / (delay_open.abs() + 1e-8)
        numerator = volume.rolling(window).mean()
        denominator = (close_minus_delay.abs() * volume).rolling(window).mean() + 1e-8
        raw = numerator / denominator
        # Rolling Rank normalization
        raw_rank = raw.rolling(window).rank(pct=True)
        signal = (raw_rank * 2) - 1
        signal = signal.fillna(0).replace([np.inf, -np.inf], 0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_011_h(df, window=20):
        _close = df['close']
