        denominator = (close_minus_delay.abs() * volume).rolling(window).mean() + 1e-8
        raw = numerator / denominator
        # Z-Score normalization then clip
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std()
        signal = ((raw - mean_raw) / (std_raw + 1e-8)).clip(-1, 1)
        signal = signal.fillna(0).replace([np.inf, -np.inf], 0)
