    @staticmethod
    def alpha_quanta_randomizer_011_r(df, window=40, p2=100):
        p1 = 0.05
        _close = df['close']
        _open = df['open']
        volume = df.get('matchingVolume', df.get('volume', 1))
        delay_open = _open.shift(1)
        close_minus_delay = (_close - delay_open) / (delay_open.abs() + 1e-8)
        numerator = volume.rolling(window).mean()
        denominator = (close_minus_delay.abs() * volume).rolling(window).mean() + 1e-8
        raw = numerator / denominator
        # Winsorized Fisher normalization
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm_val = (winsorized - low) / (high - low + 1e-9)
        signal = np.arctanh(norm_val * 1.98 - 0.99)
        signal = signal.fillna(0).replace([np.inf, -np.inf], 0)
