        ret = (close - open_1) / (open_1 + 1e-8)
        std_ret = ret.rolling(window).std()
        std_open_ret = (close / open_1 - 1).rolling(window).std() + 1e-8
        ratio_1 = std_ret / std_open_ret
        rank_1 = ratio_1.rolling(window).rank(pct=True)
        abs_ret = (ret).abs()
        numerator = volume.rolling(5).mean()
        denominator = (abs_ret * volume).rolling(5).mean() + 1e-8
        ratio_2 = numerator / denominator
        rank_2 = ratio_2.rolling(window).rank(pct=True)
        raw = rank_1 * rank_2
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -norm.ffill().fillna(0)

