    @staticmethod
    def alpha_quanta_randomizer_015_wf(df, window=60, quantile_low=0.05):
        close = df['close']
        volume = df['matchingVolume']
        ret = close.pct_change()
        std_ret = ret.rolling(window).std()
        rank_vol = volume.rolling(window).rank(pct=True)
        corr_ret_seq = ret.rolling(window).corr(pd.Series(np.arange(1, window+1), index=df.index))
        numerator = (std_ret * rank_vol).rolling(window).rank(pct=True)
        denominator = corr_ret_seq ** 2 + 1e-8
        raw = numerator / denominator
        p1 = quantile_low
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        scaled = (winsorized - low) / (high - low + 1e-9)
        result = np.arctanh(scaled * 1.98 - 0.99)
        return result.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_016_rank(df, window=15):
        # Phân tích: Tính tương quan trượt giữa tỷ suất sinh lời (return) và tỷ lệ thay đổi khối lượng (volume change ratio).
        # Bối cảnh: Dùng để đo mối quan hệ giữa giá và khối lượng, tìm điểm đồng thuận hoặc phân kỳ.
        # Chọn phương pháp chuẩn hóa A (Rolling Rank): Loại bỏ nhiễu và outlier, phù hợp với tín hiệu tương quan có phân phối không đều.
        # Xử lý: Dùng .ffill() cho NaN, .fillna(0) để neutral khi dữ liệu thiếu.
        ret = df['close'].pct_change()
        vol_change = df['matchingVolume'].pct_change()
        # Tính correlation rolling (vectorized)
        ret_mean = ret.rolling(window).mean()
        vol_mean = vol_change.rolling(window).mean()
        cov = (ret - ret_mean).mul(vol_change - vol_mean).rolling(window).sum()
        std_ret = ret.rolling(window).std()
        std_vol = vol_change.rolling(window).std()
        corr = cov / (std_ret * std_vol + 1e-9)
        # Chuẩn hóa A: Rolling Rank
        raw = corr
        ranked = raw.rolling(window).rank(pct=True)
        signal = ranked * 2 - 1
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_016_tanh(df, window=10):
        # Phân tích: Tính tương quan trượt giữa tỷ suất sinh lời và tỷ lệ thay đổi khối lượng.
        # Bối cảnh: Giống A nhưng muốn giữ lại cường độ tương quan để phản ứng mạnh với biến động lớn.
        # Chọn phương pháp B (Dynamic Tanh): Giữ magnitude, giới hạn về [-1,1] bằng tanh.
        ret = df['close'].pct_change()
        vol_change = df['matchingVolume'].pct_change()
        ret_mean = ret.rolling(window).mean()
        vol_mean = vol_change.rolling(window).mean()
        cov = (ret - ret_mean).mul(vol_change - vol_mean).rolling(window).sum()
        std_ret = ret.rolling(window).std()
        std_vol = vol_change.rolling(window).std()
        corr = cov / (std_ret * std_vol + 1e-9)
        # Chuẩn hóa B: Dynamic Tanh
        raw = corr
        signal = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_016_zscore(df, window=5):
        # Phân tích: Tính tương quan trượt giữa tỷ suất sinh lời và tỷ lệ thay đổi khối lượng.
        # Bối cảnh: Giá trị corr là dạng oscillator quanh 0, phù hợp với chuẩn hóa Z-score.
        # Chọn phương pháp C (Rolling Z-Score/Clip): Dùng cho dạng spread/tương quan dạng oscillator.
        ret = df['close'].pct_change()
        vol_change = df['matchingVolume'].pct_change()
        ret_mean = ret.rolling(window).mean()
        vol_mean = vol_change.rolling(window).mean()
        cov = (ret - ret_mean).mul(vol_change - vol_mean).rolling(window).sum()
        std_ret = ret.rolling(window).std()
        std_vol = vol_change.rolling(window).std()
        corr = cov / (std_ret * std_vol + 1e-9)
        # Chuẩn hóa C: Rolling Z-score và clip
        raw = corr
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)
        signal = zscore.clip(-1, 1)
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_016_sign(df, window=10):
        # Phân tích: Tính tương quan trượt giữa tỷ suất sinh lời và tỷ lệ thay đổi khối lượng.
        # Bối cảnh: Chỉ quan tâm hướng tương quan dương hay âm (phân kỳ/đồng thuận).
        # Chọn phương pháp D (Sign/Binary Soft): Đơn giản hóa thành +1 (đồng thuận) hoặc -1 (phân kỳ).
        ret = df['close'].pct_change()
        vol_change = df['matchingVolume'].pct_change()
        ret_mean = ret.rolling(window).mean()
        vol_mean = vol_change.rolling(window).mean()
        cov = (ret - ret_mean).mul(vol_change - vol_mean).rolling(window).sum()
        std_ret = ret.rolling(window).std()
        std_vol = vol_change.rolling(window).std()
        corr = cov / (std_ret * std_vol + 1e-9)
        # Chuẩn hóa D: np.sign
        raw = corr
        signal = pd.Series(np.sign(raw), index=df.index)
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_016_wf(df, window=10, p1=0.3):
        # Phân tích: Tính tương quan trượt giữa tỷ suất sinh lời và tỷ lệ thay đổi khối lượng.
        # Bối cảnh: Dữ liệu tương quan có thể có heavy tails do biến động mạnh, cần giữ cấu trúc phân phối.
        # Chọn phương pháp E (Winsorized Fisher): Xử lý outlier bằng winsorizing rồi Fisher transform.
        p2 = window
        ret = df['close'].pct_change()
        vol_change = df['matchingVolume'].pct_change()
        ret_mean = ret.rolling(window).mean()
        vol_mean = vol_change.rolling(window).mean()
        cov = (ret - ret_mean).mul(vol_change - vol_mean).rolling(window).sum()
        std_ret = ret.rolling(window).std()
        std_vol = vol_change.rolling(window).std()
        corr = cov / (std_ret * std_vol + 1e-9)
        raw = corr
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher transform
        scaled = (winsorized - low) / (high - low + 1e-9)
        signal = np.arctanh(scaled * 1.98 - 0.99)
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_017_rank(df, window=65):
        raw = df['close'].rolling(5).mean() - df['close'].rolling(10).mean().rolling(5).mean()
        raw = (raw / (df['close'].rolling(20).std() + 1e-8)) * np.sign(((df['high'] - df['low']) / (df['high'].rolling(10).mean() - df['low'].rolling(10).mean()) - 1))
        return -(raw.rolling(window).rank(pct=True) * 2 - 1).fillna(0)

