    @staticmethod
    def alpha_quanta_randomizer_017_wf(df, window_quantile=90, quantile_factor=0.9):
        raw = df['close'].rolling(5).mean() - df['close'].rolling(10).mean().rolling(5).mean()
        raw = (raw / (df['close'].rolling(20).std() + 1e-8)) * np.sign(((df['high'] - df['low']) / (df['high'].rolling(10).mean() - df['low'].rolling(10).mean()) - 1))
        low = raw.rolling(window_quantile).quantile(quantile_factor)
        high = raw.rolling(window_quantile).quantile(1 - quantile_factor)
        winsorized = raw.clip(upper=high, lower=low)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0).replace([np.inf, -np.inf], 0)

