        delta_close = close.diff(1) / (close + 1e-8)
        delta_volume = volume.diff(1) / (volume + 1e-8)
        corr_short = delta_close.rolling(window_corr_short).corr(delta_volume)
        corr_long = delta_close.rolling(window_corr_long).corr(delta_volume)
        raw = corr_short - corr_long
        normalized = (raw.rolling(20).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

