    @staticmethod
    def alpha_quanta_randomizer_031_rank(df, window=15):
        high = df['high']
        low = df['low']
        close = df['close']
        # Handle missing columns
        vwap = df.get('vwap', (high + low + close) / 3)
        amount = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        # Compute range
        range_ = high - low
        # Create sequence 1..window
        seq = pd.Series(np.arange(1, window+1), index=df.index[:window])
        seq = seq.reindex(df.index, method='ffill')
        # Rolling correlation between range and sequence
        range_rolling = range_.rolling(window)
        seq_rolling = seq.rolling(window)
        corr = range_rolling.corr(seq_rolling)
        # Compute sign of mean return over 5 periods
        ret = close.pct_change()
        mean_ret_5 = ret.rolling(5).mean()
        sign_mean_ret = np.sign(mean_ret_5)
        # Raw signal
        raw = corr * sign_mean_ret
        # Normalize with Rolling Rank (Case A)
        normalized = raw.rolling(window).rank(pct=True) * 2 - 1
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_031_tanh(df, window=15):
        high = df['high']
        low = df['low']
        close = df['close']
        vwap = df.get('vwap', (high + low + close) / 3)
        amount = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        range_ = high - low
        seq = pd.Series(np.arange(1, window+1), index=df.index[:window])
        seq = seq.reindex(df.index, method='ffill')
        corr = range_.rolling(window).corr(seq.rolling(window))
        ret = close.pct_change()
        mean_ret_5 = ret.rolling(5).mean()
        sign_mean_ret = np.sign(mean_ret_5)
        raw = corr * sign_mean_ret
        # Normalize with Dynamic Tanh (Case B)
        std = raw.rolling(window).std()
        normalized = np.tanh(raw / std.replace(0, np.nan))
        normalized = normalized.ffill().fillna(0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_031_zscore(df, window=15):
        high = df['high']
        low = df['low']
        close = df['close']
        vwap = df.get('vwap', (high + low + close) / 3)
        amount = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        range_ = high - low
        seq = pd.Series(np.arange(1, window+1), index=df.index[:window])
        seq = seq.reindex(df.index, method='ffill')
        corr = range_.rolling(window).corr(seq.rolling(window))
        ret = close.pct_change()
        mean_ret_5 = ret.rolling(5).mean()
        sign_mean_ret = np.sign(mean_ret_5)
        raw = corr * sign_mean_ret
        # Normalize with Rolling Z-Score Clip (Case C)
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std()
        normalized = ((raw - mean) / std.replace(0, np.nan)).clip(-1, 1)
        normalized = normalized.ffill().fillna(0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_031_sign(df, window=15):
        high = df['high']
