    @staticmethod
    def alpha_quanta_randomizer_031_wf(df, window=15, p1=0.05):
        high = df['high']
        low = df['low']
        close = df['close']
        vwap = df.get('vwap', (high + low + close) / 3)
        amount = df.get('amount', close * df.get('matchingVolume', df.get('volume', 1)))
        range_ = high - low
        seq = pd.Series(np.arange(1, window+1), index=df.index[:window])
        seq = seq.reindex(df.index, method='ffill')
        corr = range_.rolling(window).corr(seq.rolling(window))
        ret = close.pct_change()
        mean_ret_5 = ret.rolling(5).mean()
        sign_mean_ret = np.sign(mean_ret_5)
        raw = corr * sign_mean_ret
        # Normalize with Winsorized Fisher (Case E)
        p2 = window
        low_q = raw.rolling(p2).quantile(p1)
        high_q = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_q, upper=high_q, axis=0)
        normalized = np.arctanh(((winsorized - low_q) / (high_q - low_q + 1e-9)) * 1.98 - 0.99)
        normalized = normalized.ffill().fillna(0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_032_rank(df, window=40):
        volume = df.get('matchingVolume', df.get('volume', 1))
        volume_series = volume.ffill().fillna(volume.median())
        close = df['close'].ffill().fillna(method='bfill')
        ret = close.pct_change()
        ret[ret == 0] = np.nan
        ret = ret.ffill().fillna(0)
        vol_pct = volume_series.pct_change(window).replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        ret_std = ret.rolling(window).std().replace(0, np.nan).ffill().fillna(1)
        raw = (vol_pct / (ret_std + 1e-8)).fillna(0)
        ranked = raw.rolling(window).rank(pct=True).fillna(0.5)
        signal = (ranked * 2) - 1
        return -signal

