    @staticmethod
    def alpha_quanta_randomizer_032_wf(df, window=100, winsor_percentile=0.3):
        volume = df.get('matchingVolume', df.get('volume', 1))
        volume_series = volume.ffill().fillna(volume.median())
        close = df['close'].ffill().fillna(method='bfill')
        ret = close.pct_change()
        ret[ret == 0] = np.nan
        ret = ret.ffill().fillna(0)
        vol_pct = volume_series.pct_change(window).replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        ret_std = ret.rolling(window).std().replace(0, np.nan).ffill().fillna(1)
        raw = (vol_pct / (ret_std + 1e-8)).fillna(0)
        low = raw.rolling(window).quantile(winsor_percentile).fillna(method='bfill').fillna(raw.min())
        high = raw.rolling(window).quantile(1 - winsor_percentile).fillna(method='bfill').fillna(raw.max())
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        denominator = (high - low).replace(0, np.nan).ffill().fillna(1)
        normalized = np.arctanh(((winsorized - low) / (denominator + 1e-9)) * 1.98 - 0.99)
        normalized = normalized.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        signal = normalized.clip(-1, 1)
        return -signal

