    @staticmethod
    def alpha_quanta_randomizer_043_rank(df, window=40, sub_window=1):
        close = df['close']
        mean_close = close.rolling(window).mean()
        ratio = close / (mean_close + 1e-8)
        zscore = (ratio - ratio.rolling(window).mean()) / ratio.rolling(window).std().replace(0, np.nan)
        sign = np.sign(zscore)
        ret = close.pct_change()
        sum_ret = ret.rolling(sub_window).sum()
        raw = -sign * sum_ret
        result = raw.rolling(window).rank(pct=True).fillna(0) * 2 - 1
        return result.fillna(0)

