        ret2 = ret.loc[valid]
        vol_mean = vol_ratio2.rolling(window).mean()
        ret_mean = ret2.rolling(window).mean()
        cov = ((vol_ratio2 - vol_mean) * (ret2 - ret_mean)).rolling(window).mean()
        std_vol = vol_ratio2.rolling(window).std(ddof=0)
        std_ret = ret2.rolling(window).std(ddof=0)
        corr = cov / (std_vol * std_ret + 1e-8)
        signal = corr.reindex(df.index).fillna(0)
        raw = np.tanh(signal / signal.rolling(window).std().replace(0, np.nan).fillna(1e-8))
        return raw.fillna(0)

