    @staticmethod
    def alpha_quanta_randomizer_045_wf(df, window_rank=60, p1=0.9):
        p2 = window_rank
        volume = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        ret = close.pct_change()
        vol_ratio = volume / (volume.rolling(60).mean() + 1e-8) - 1
        valid = vol_ratio.dropna().index.intersection(ret.dropna().index)
        vol_ratio2 = vol_ratio.loc[valid]
        ret2 = ret.loc[valid]
        vol_mean = vol_ratio2.rolling(window_rank).mean()
        ret_mean = ret2.rolling(window_rank).mean()
        cov = ((vol_ratio2 - vol_mean) * (ret2 - ret_mean)).rolling(window_rank).mean()
        std_vol = vol_ratio2.rolling(window_rank).std(ddof=0)
        std_ret = ret2.rolling(window_rank).std(ddof=0)
        corr = cov / (std_vol * std_ret + 1e-8)
        signal = corr.reindex(df.index).fillna(0)
        low = signal.rolling(p2).quantile(p1)
        high = signal.rolling(p2).quantile(1 - p1)
        winsorized = signal.clip(lower=low, upper=high, axis=0)
        norm = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        raw = np.arctanh(norm.clip(-0.99, 0.99))
        return -raw.fillna(0)

