    def alpha_quanta_randomizer_046_rank(df, window=10):
        spread = df['high'] - df['low']
        mean_spread = spread.rolling(window=window).mean()
        raw = spread / (mean_spread + 1e-8)
        norm_60 = raw.rolling(window).std() + 1e-8
        final_raw = raw.rolling(10).mean() / norm_60
        result = (final_raw.rolling(20).rank(pct=True) * 2) - 1
        return result.fillna(0)

