    @staticmethod
    def alpha_quanta_randomizer_048_wf(df, window=100, p1=0.3, p2=20):
        data = (df['high'] - df['low']) / (df['low'] + 1e-8)
        vol_delta = (df['matchingVolume'].diff() / (df['matchingVolume'] + 1e-8))
        x_avg = data.rolling(window).mean()
        y_avg = vol_delta.rolling(window).mean()
        x_std = data.rolling(window).std(ddof=0)
        y_std = vol_delta.rolling(window).std(ddof=0)
        cov = data.rolling(window).cov(vol_delta)
        corr = cov / (x_std * y_std + 1e-8)
        raw = -corr
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        temp = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        temp = temp.clip(-0.99, 0.99)
        signal = np.arctanh(temp)
        signal = signal / np.max(np.abs(signal)) if np.max(np.abs(signal)) != 0 else signal
        return signal.ffill().fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_049_rank(df, window_rank=30):
        raw = (df['close'] / (df['high'] - df['low']).rolling(window=window_rank).mean().replace(0, np.nan) + 1e-8) - (df['close'] / (df['high'] - df['low']).rolling(window=window_rank).mean().replace(0, np.nan) + 1e-8).rolling(window=window_rank).median()
        raw = raw.abs()
        signal = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        return signal.fillna(0)

