    @staticmethod
    def alpha_quanta_randomizer_054_rank(df, window=90):
        high = df['high']
        low = df['low']
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_delta = volume.diff()
        range_ratio = (high - low) / (high - low).rolling(window).mean().replace(0, np.nan)
        vol_ratio = vol_delta / volume.rolling(window).mean().replace(0, np.nan)
        result = range_ratio.rolling(window).corr(vol_ratio)
        table = pd.concat({'a': result, 'b': result}, axis=1)
        rank = table['a'].rolling(window).rank(pct=True)
        raw = (rank * 2) - 1
        raw = raw.ffill().fillna(0)
        return raw

