    @staticmethod
    def alpha_quanta_randomizer_055_wf(df, window=50, p1=0.7):
        raw = (df['high'] - df['low']).rolling(window).mean() / ((df['high'] - df['low']).rolling(window).std() + 1e-8)
        low = raw.rolling(window).quantile(p1)
        high = raw.rolling(window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(method='ffill').fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_056_rank(df, window=15):
        # Tính slope của linear regression với x = ngày (0-4)
        days = pd.Series(np.arange(5) - 2, index=df.index)
        ret = df['close'] / df['open'] - 1
        # Tính covariance và variance trên rolling window
        cov = ret.rolling(window).cov(days)
        var = days.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        # Rolling Rank normalization (Case A)
        normalized = (slope.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_056_tanh(df, window=15):
        days = pd.Series(np.arange(5) - 2, index=df.index)
        ret = df['close'] / df['open'] - 1
        cov = ret.rolling(window).cov(days)
        var = days.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        # Dynamic Tanh normalization (Case B)
        std = slope.rolling(window).std().replace(0, np.nan)
        normalized = np.tanh(slope / std)
        return normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_056_zscore(df, window=15):
        days = pd.Series(np.arange(5) - 2, index=df.index)
        ret = df['close'] / df['open'] - 1
        cov = ret.rolling(window).cov(days)
        var = days.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        # Rolling Z-Score/Clip normalization (Case C)
        mean = slope.rolling(window).mean()
        std = slope.rolling(window).std().replace(0, np.nan)
        normalized = ((slope - mean) / std).clip(-1, 1)
        return normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_056_sign(df, window=15):
        days = pd.Series(np.arange(5) - 2, index=df.index)
        ret = df['close'] / df['open'] - 1
        cov = ret.rolling(window).cov(days)
        var = days.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        # Sign/Binary Soft normalization (Case D)
        normalized = np.sign(slope)
        return normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_056_wf(df, window=15, p1=0.05):
        days = pd.Series(np.arange(5) - 2, index=df.index)
        ret = df['close'] / df['open'] - 1
        cov = ret.rolling(window).cov(days)
        var = days.rolling(window).var().replace(0, np.nan)
        slope = cov / var
        # Winsorized Fisher normalization (Case E)
        low = slope.rolling(window).quantile(p1)
        high = slope.rolling(window).quantile(1 - p1)
        winsorized = slope.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_057_rank(df, window=50):
        close = df['close']
        volume = df['matchingVolume']
        _return = close.pct_change()
        mean_ret = _return.rolling(window).mean()
        corr = close.rolling(window).corr(volume)
        std_vol = volume.rolling(window*2).std()
        raw = np.sign(mean_ret) * corr * (1 + 1/(std_vol + 1))
        normalized = raw.fillna(0)
        normalized = (normalized - normalized.min()) / (normalized.max() - normalized.min() + 1e-9) * 2 - 1
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_057_tanh(df, window=20):
        close = df['close']
        volume = df['matchingVolume']
        _return -= close.pct_change()
        mean_ret = _return.rolling(window).mean()
        corr = close.rolling(window).corr(volume)
        std_vol = volume.rolling(window*2).std()
        raw = np.sign(mean_ret) * corr * (1 + 1/(std_vol + 1))
        nan_mask = raw.isna()
        raw_filled = raw.fillna(0)
        rolling_std = raw_filled.rolling(window).std().replace(0, np.nan).ffill().fillna(1)
        normalized = np.tanh(raw_filled / rolling_std)
        normalized = normalized.where(~nan_mask, 0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_057_zscore(df, window=85):
        close = df['close']
        volume = df['matchingVolume']
        _return -= close.pct_change()
        mean_ret = _return.rolling(window).mean()
        corr = close.rolling(window).corr(volume)
        std_vol = volume.rolling(window*2).std()
        raw = np.sign(mean_ret) * corr * (1 + 1/(std_vol + 1))
        rolling_mean = raw.rolling(window).mean()
        rolling_std = raw.rolling(window).std().replace(0, np.nan).ffill().fillna(1)
        normalized = ((raw - rolling_mean) / rolling_std).clip(-1, 1)
        normalized = normalized.fillna(0)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_057_sign(df, window=70):
        close = df['close']
