        denom = df['matchingVolume'].rolling(10).std() + 1
        raw = raw / denom
        raw = raw.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
