    @staticmethod
    def alpha_quanta_randomizer_060_0(df, window=35):
        # Calculate returns
        returns = df['close'].pct_change().fillna(0)
        # Calculate rolling sum and standard deviation
        rolling_sum = returns.rolling(window).sum()
        rolling_std = returns.rolling(window).std()
        # Compute raw signal
        raw = rolling_sum / (rolling_std + 1e-8) * np.sign(rolling_sum)
        # Normalize using Rolling Z-Score (Method C)
        signal = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std()).clip(-1, 1)
        # Fill NaN
        signal = signal.fillna(0)
        return signal

