    @staticmethod
    def alpha_quanta_randomizer_060_wf(df, window=20, winsor_window=100):
        close = df['close']
        returns = close.pct_change().replace([np.inf, -np.inf], np.nan)
        ret_sum = returns.rolling(window).sum()
        ret_std = returns.rolling(window).std().replace(0, np.nan)
        raw = (ret_sum / ret_std) * np.sign(ret_sum)
        low = raw.rolling(winsor_window).quantile(0.05)
        high = raw.rolling(winsor_window).quantile(0.95)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm_low = low.copy()
        norm_high = high.copy()
        norm = np.arctanh(((winsorized - norm_low) / (norm_high - norm_low + 1e-9)) * 1.98 - 0.99)
        return norm.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_061_rank(df, window=85):
        vol = df.get('matchingVolume', df.get('volume', 0))
        delta_vol = vol.diff(1).fillna(0)
        delay_delta_vol = delta_vol.shift(1).fillna(0)
        corr = delta_vol.rolling(window).cov(delay_delta_vol) / (delta_vol.rolling(window).std().replace(0, np.nan) * delay_delta_vol.rolling(window).std().replace(0, np.nan))
        corr = corr.fillna(0)
        signal = (corr.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0).replace([np.inf, -np.inf], 0)
        return -signal

