    @staticmethod
    def alpha_quanta_randomizer_061_wf(df, window=60, quantile=0.1):
        vol = df.get('matchingVolume', df.get('volume', 0))
        delta_vol = vol.diff(1).fillna(0)
        delay_delta_vol = delta_vol.shift(1).fillna(0)
        corr = delta_vol.rolling(window).cov(delay_delta_vol) / (delta_vol.rolling(window).std().replace(0, np.nan) * delay_delta_vol.rolling(window).std().replace(0, np.nan))
        corr = corr.fillna(0)
        p2 = window
        low = corr.rolling(p2).quantile(quantile)
        high = corr.rolling(p2).quantile(1 - quantile)
        winsorized = corr.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
