    @staticmethod
    def alpha_quanta_randomizer_062_rank(df, window=30, sub_window=20):
        high = df['high']
        low = df['low']
        close = df['close']
        max_high = high.rolling(window).max()
        min_low = low.rolling(window).min()
        mean_bounds = (max_high + min_low).rolling(sub_window).mean()
        std_close = close.rolling(window).std().replace(0, np.nan)
        raw = (close - mean_bounds) / (std_close + 1e-8)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0).ffill()

    @staticmethod
    def alpha_quanta_randomizer_062_tanh(df, window=40, sub_window=5):
        high = df['high']
        low = df['low']
        close = df['close']
        max_high = high.rolling(window).max()
        min_low = low.rolling(window).min()
        mean_bounds = (max_high + min_low).rolling(sub_window).mean()
        std_close = close.rolling(window).std().replace(0, np.nan)
        raw = (close - mean_bounds) / (std_close + 1e-8)
        normalized = np.tanh(raw / raw.rolling(window).std())
        return normalized.fillna(0).ffill()

    @staticmethod
    def alpha_quanta_randomizer_062_zscore(df, window=60, sub_window=10):
        high = df['high']
