    @staticmethod
    def alpha_quanta_randomizer_062_wf(df, window=30, sub_window=40, p1=0.05):
        high = df['high']
        low = df['low']
        close = df['close']
        max_high = high.rolling(window).max()
        min_low = low.rolling(window).min()
        mean_bounds = (max_high + min_low).rolling(sub_window).mean()
        std_close = close.rolling(window).std().replace(0, np.nan)
        raw = (close - mean_bounds) / (std_close + 1e-8)
        p2 = int(window * 1.5)
        low_raw = raw.rolling(p2).quantile(p1)
        high_raw = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_raw, upper=high_raw, axis=0)
        normalized = np.arctanh(((winsorized - low_raw) / (high_raw - low_raw + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0).ffill()

    @staticmethod
    def alpha_quanta_randomizer_063_rank(df, window=45):
        ret = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        corr = ret.rolling(window).corr(ret.shift(1))
        raw = corr.rank(pct=True)
        # Chuẩn hóa về [-1, 1]
        signal = (raw * 2) - 1
        return -signal.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_063_tanh(df, window=60):
        ret = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        corr = ret.rolling(window).corr(ret.shift(1))
        raw = corr.rolling(window).std()
        # Chuẩn hóa Dynamic Tanh
        signal = np.tanh(corr / (raw + 1e-9))
        return -signal.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_063_zscore(df, window=90):
        ret = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        corr = ret.rolling(window).corr(ret.shift(1))
        mean_corr = corr.rolling(window).mean()
        std_corr = corr.rolling(window).std()
        # Chuẩn hóa Rolling Z-Score
        signal = ((corr - mean_corr) / (std_corr + 1e-9)).clip(-1, 1)
        return -signal.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_063_sign(df, window=65):
        ret = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
