    @staticmethod
    def alpha_quanta_randomizer_064_wf(df, window=100, p1=0.7):
        p2 = window
        hl_ratio = (df['high'] - df['low']) / (df['high'] + df['low'] + 1e-8)
        ts_std = hl_ratio.rolling(5).std()
        days = pd.Series(np.arange(len(df)), index=df.index)
