    def alpha_quanta_randomizer_067_rank(df, window=15):
        ret = df['close'].pct_change()
        volume = df.get('matchingVolume', df.get('volume', pd.Series(1, index=df.index)))
        ts_mean = ret.rolling(window).mean()
        ts_corr = ret.rolling(window).corr(volume.apply(pd.Series.rank if volume.ndim == 1 else lambda x: volume)) if volume.ndim == 1 else ret.rolling(window).corr(volume)
        sign_corr = np.sign(ts_corr)
        raw = ts_mean * sign_corr
