        sign_corr = np.sign(ts_corr)
        raw = ts_mean * sign_corr
        low = raw.rolling(2 * window).quantile(p)
        high = raw.rolling(2 * window).quantile(1 - p)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
