        raw = (ts_max / ts_mean) * ts_std
        raw = raw.rolling(2).mean().fillna(method='ffill').fillna(0)
        result = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)).clip(-1, 1)
        return result.fillna(0)

