    @staticmethod
    def alpha_quanta_randomizer_075_rank(df, window=60):
        high_low = df['high'] - df['low']
        std_hl = high_low.rolling(window).std()
        vol_range_ratio = df['matchingVolume'] / (high_low.replace(0, np.nan).ffill().fillna(1e-8) + 1e-8)
        mean_vol_range = np.log1p(vol_range_ratio).rolling(window).mean()
        raw = std_hl / (mean_vol_range + 1e-8)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0).clip(-1, 1)

