    @staticmethod
    def alpha_quanta_randomizer_075_wf(df, window=50, p1=0.7):
        p2 = int(window * 2) if window * 2 > 1 else 2
        high_low = df['high'] - df['low']
        std_hl = high_low.rolling(window).std()
        vol_range_ratio = df['matchingVolume'] / (high_low.replace(0, np.nan).ffill().fillna(1e-8) + 1e-8)
        mean_vol_range = np.log1p(vol_range_ratio).rolling(window).mean()
        raw = std_hl / (mean_vol_range + 1e-8)
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        range_h_l = (high - low + 1e-9)
        normalized = np.arctanh(((winsorized - low) / range_h_l) * 1.98 - 0.99)
        signal = normalized.clip(-1, 1).fillna(0).replace([np.inf, -np.inf], 0)
        return -signal

