    @staticmethod
    def alpha_quanta_randomizer_081_rank(df, window=80, sub_window=30):
        close = df['close']
        volume = df['matchingVolume']
        delta_close = close.diff(5)
        zscore_delta = (delta_close - delta_close.rolling(sub_window).mean()) / delta_close.rolling(sub_window).std().replace(0, np.nan)
        ts_std_vol = volume.rolling(sub_window).std()
        zscore_vol = (ts_std_vol - ts_std_vol.rolling(sub_window).mean()) / ts_std_vol.rolling(sub_window).std().replace(0, np.nan)
        returns = close.pct_change()
        delay_return = returns.shift(1)
        corr1 = zscore_delta.rolling(window).corr(delay_return)
        corr2 = zscore_vol.rolling(window).corr(delay_return)
        raw = corr1 * zscore_delta + corr2 * zscore_vol
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

