        delta_vol = volume.diff(1)
        hl_range = high - low
        corr = delta_vol.rolling(window).corr(hl_range)
        raw = zscore * corr
        # Dynamic Tanh normalization
        signal = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        signal = signal.fillna(0)
        return signal

