    @staticmethod
    def alpha_quanta_randomizer_082_wf(df, window=10):
        close = df['close']
        volume = df['matchingVolume']
        high = df['high']
        low = df['low']
        ts_rank_close = close.rolling(window).rank(pct=True)
        mean_rank = ts_rank_close.rolling(window).mean()
        std_rank = ts_rank_close.rolling(window).std().replace(0, np.nan)
        zscore = (ts_rank_close - mean_rank) / std_rank
        delta_vol = volume.diff(1)
        hl_range = high - low
        corr = delta_vol.rolling(window).corr(hl_range)
        raw = zscore * corr
        # Winsorized Fisher normalization
        p1 = 0.05
        p2 = window
        low_perc = raw.rolling(p2).quantile(p1)
        high_perc = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low_perc, upper=high_perc, axis=0)
        normalized = np.arctanh(((winsorized - low_perc) / (high_perc - low_perc + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0).clip(-1, 1)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_083_rank(df, window=10):
        close = df['close']
        open_ = df['open']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = (close.pct_change().fillna(0))
        delay_ret = ret.shift(1).fillna(0)
        abs_delta = (close - open_).abs()
        sign_delta = np.sign(close - open_)
        term1_abs = (sign_delta * abs_delta.rolling(5).mean()).rolling(window).corr(delay_ret).abs()
        term1 = term1_abs * sign_delta * abs_delta.rolling(5).mean()
        vol_mean = volume.rolling(5).mean()
        vol_std = volume.rolling(5).std().replace(0, np.nan).ffill().fillna(0)
        vol_ratio = vol_mean / (vol_std + 1e-8)
        term2_abs = vol_ratio.rolling(window).corr(delay_ret).abs()
        term2 = term2_abs * vol_ratio
        raw = term1 + term2
        raw = raw.fillna(0)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

