    @staticmethod
    def alpha_quanta_randomizer_087_r(df, p1=0.05):
        window = 20
        valid_window = min(window, len(df))
        if valid_window < 2:
            return pd.Series(np.zeros(len(df)), index=df.index)
        if len(df) < 2:
            return pd.Series(np.zeros(len(df)), index=df.index)
        upper = (df['high'] - df['low']).replace(0, np.nan)
        raw_hl = (df['close'] - df['low']) / (upper + 1e-8)
        raw_hl = raw_hl.ffill().fillna(0.5)
        raw_ma = raw_hl.rolling(10).mean().ffill().fillna(0.5)
        raw_std = df['volume'].rolling(10).std().ffill().fillna(df['volume'].mean())
        ratio = raw_ma / (raw_std + 1e-8)
        rolling_corr = (df['close'] * df['volume']).rolling(10).mean()
        rolling_corr = rolling_corr.ffill().fillna(0)
        combined = ratio * rolling_corr
        low = combined.rolling(valid_window).quantile(p1).ffill().fillna(combined.min())
        high = combined.rolling(valid_window).quantile(1 - p1).ffill().fillna(combined.max())
        winsorized = combined.clip(lower=low, upper=high, axis=0)
        scaled = ((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99
        signal = np.arctanh(np.clip(scaled, -0.99, 0.99))
        return signal.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_088_rank(df, window=25):
        close = df['close']
        volume = df['matchingVolume']
        high = df['high']
        low = df['low']
        delta_vol = np.sign(close.diff(1))
        ts_mean_v = volume.rolling(window).mean()
        hilo = high - low
        ts_std_hilo = hilo.rolling(window).std(ddof=0)
        scalar = ts_mean_v / (ts_std_hilo + 1e-8)
        raw = delta_vol * scalar
        ts_mean_hilo = hilo.rolling(20).mean()
        cond = (ts_std_hilo < ts_mean_hilo).astype(int)
        raw_cond = raw * cond
        rank_raw = raw_cond.rolling(window).rank(pct=True) * 2 - 1
        rank_raw = rank_raw.fillna(0)
        return rank_raw

