    @staticmethod
    def alpha_quanta_randomizer_088_wf(df, window=20, p1=0.1):
        close = df['close']
        volume = df['matchingVolume']
        high = df['high']
        low = df['low']
        delta_vol = np.sign(close.diff(1))
        ts_mean_v = volume.rolling(window).mean()
        hilo = high - low
        ts_std_hilo = hilo.rolling(window).std(ddof=0)
        raw = delta_vol * (ts_mean_v / (ts_std_hilo + 1e-8))
        ts_mean_hilo = hilo.rolling(20).mean()
        cond = (ts_std_hilo < ts_mean_hilo).astype(int)
        raw_cond = raw * cond
        p2 = window * 4
        low_q = raw_cond.rolling(p2).quantile(p1)
        high_q = raw_cond.rolling(p2).quantile(1 - p1)
        winsorized = raw_cond.clip(lower=low_q, upper=high_q, axis=0)
        epsilon = 1e-9
        normalized = np.arctanh(((winsorized - low_q) / (high_q - low_q + epsilon)) * 1.98 - 0.99)
        normalized = normalized.replace([np.inf, -np.inf], np.nan).fillna(0)
        return normalized

