    @staticmethod
    def alpha_quanta_randomizer_092_rank(df, window=65):
        high = df['high']
        low = df['low']
        volume = df['matchingVolume']
        close = df['close']
        ret = close.pct_change()
        # Step 1: ($high - $low) / ($high + 1e-8)
        hl_ratio = (high - low) / (high + 1e-8)
        # Step 2: TS_ZSCORE($volume, 10)
        vol_zscore = (volume - volume.rolling(10).mean()) / volume.rolling(10).std().replace(0, np.nan)
        # Step 3: TS_CORR(hl_ratio, vol_zscore, 20)
        corr_series = hl_ratio.rolling(window).corr(vol_zscore)
        # Step 4: RANK(corr_series)
        rank_corr = corr_series.rank(pct=True)
        # Step 5: SIGN($return)
        sign_ret = np.sign(ret)
        # Final signal
        raw = rank_corr * sign_ret
        # Normalization Method A: Rolling Rank
        signal = raw.rolling(window).rank(pct=True) * 2 - 1
        signal = signal.fillna(0)
        return signal

