    @staticmethod
    def alpha_quanta_randomizer_098_rank(df, window=40):
        volume = df.get('matchingVolume', df.get('volume', 1)).fillna(0)
        log_vol = np.log(volume + 1e-8)
        delta_log_vol = log_vol.diff(1)
        hl_range = (df['high'] - df['low']) / (df['close'] + 1e-8)
        x = delta_log_vol
        y = hl_range
        x_mean = x.rolling(window).mean()
        y_mean = y.rolling(window).mean()
        num = ((x - x_mean) * (y - y_mean)).rolling(window).sum()
        den = np.sqrt(((x - x_mean)**2).rolling(window).sum() * ((y - y_mean)**2).rolling(window).sum() + 1e-9)
        raw = num / den
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

