    @staticmethod
    def alpha_quanta_randomizer_100_wf(df, window=70, p=0.1):
        raw = np.sign(df['close'].diff(1))
        close_vol = df['close'] * df.get('matchingVolume', df.get('volume', df['close'] * 1e6))
        mean_cv = close_vol.rolling(window).mean()
        ratio = close_vol / (mean_cv + 1e-8)
        zscore = (ratio - ratio.rolling(window).mean()) / ratio.rolling(window).std()
        result = raw * zscore
        low = result.rolling(window).quantile(p)
        high = result.rolling(window).quantile(1 - p)
        winsorized = result.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_101_rank(df, window=10):
        assert isinstance(df, pd.DataFrame), 'df phải là pd.DataFrame'
        assert 'high' in df.columns and 'low' in df.columns and 'volume' in df.columns, 'Thiếu cột high, low, volume'
        spread_vol = (df['high'] - df['low']) / (df.get('volume', df.get('matchingVolume', df.get('matchingVolume', 1))) + 1e-8)
        delta_spread = spread_vol.diff(window).fillna(0)
        ts_mean_spread = spread_vol.rolling(window).mean().fillna(0)
        raw = delta_spread * ts_mean_spread
        mu = raw.rolling(window).mean()
        sigma = raw.rolling(window).std().replace(0, np.nan).ffill()
        zscore = (raw - mu) / sigma
        zscore = zscore.fillna(0)
        normalized = (zscore.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_101_tanh(df, window=10):
        assert isinstance(df, pd.DataFrame), 'df phải là pd.DataFrame'
        assert 'high' in df.columns and 'low' in df.columns and 'volume' in df.columns, 'Thiếu cột high, low, volume'
        spread_vol = (df['high'] - df['low']) / (df.get('volume', df.get('matchingVolume', 1)) + 1e-8)
        delta_spread = spread_vol.diff(window).fillna(0)
        ts_mean_spread = spread_vol.rolling(window).mean().fillna(0)
        raw = delta_spread * ts_mean_spread
        normalized = np.tanh(raw / (raw.rolling(window).std().replace(0, np.nan).ffill() + 1e-8))
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_101_zscore(df, window=10):
        assert isinstance(df, pd.DataFrame), 'df phải là pd.DataFrame'
        assert 'high' in df.columns and 'low' in df.columns and 'volume' in df.columns, 'Thiếu cột high, low, volume'
        spread_vol = (df['high'] - df['low']) / (df.get('volume', df.get('matchingVolume', 1)) + 1e-8)
        delta_spread = spread_vol.diff(window).fillna(0)
        ts_mean_spread = spread_vol.rolling(window).mean().fillna(0)
        raw = delta_spread * ts_mean_spread
        mu = raw.rolling(window).mean()
        sigma = raw.rolling(window).std().replace(0, np.nan).ffill()
        normalized = ((raw - mu) / sigma).clip(-1, 1)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_101_sign(df, window=10):
        assert isinstance(df, pd.DataFrame), 'df phải là pd.DataFrame'
        assert 'high' in df.columns and 'low' in df.columns and 'volume' in df.columns, 'Thiếu cột high, low, volume'
        spread_vol = (df['high'] - df['low']) / (df.get('volume', df.get('matchingVolume', 1)) + 1e-8)
        delta_spread = spread_vol.diff(window).fillna(0)
        ts_mean_spread = spread_vol.rolling(window).mean().fillna(0)
        raw = delta_spread * ts_mean_spread
        normalized = np.sign(raw) * np.clip(np.abs(raw) / (raw.rolling(window).std().replace(0, np.nan).ffill() + 1e-8), 0, 1)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_101_wf(df, window=10, quantile_low=0.1):
        assert isinstance(df, pd.DataFrame), 'df phải là pd.DataFrame'
        assert 'high' in df.columns and 'low' in df.columns and 'volume' in df.columns, 'Thiếu cột high, low, volume'
        spread_vol = (df['high'] - df['low']) / (df.get('volume', df.get('matchingVolume', 1)) + 1e-8)
        delta_spread = spread_vol.diff(window).fillna(0)
        ts_mean_spread = spread_vol.rolling(window).mean().fillna(0)
        raw = delta_spread * ts_mean_spread
        low = raw.rolling(window).quantile(quantile_low)
        high = raw.rolling(window).quantile(1 - quantile_low)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_102_rank(df, window=75):
        # Tinh TS_STD va TS_MEAN cua close
        std_close = df['close'].rolling(window).std()
        mean_close = df['close'].rolling(window).mean()
        # Tranh chia cho 0
        ratio = std_close / (mean_close + 1e-8)
        # Tinh delta volume
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_volume = volume.diff(1) / (volume + 1e-8)
        # Tinh rolling correlation giua ratio va delta_volume
        # Su dung pandas vectorized rolling corr
        raw = ratio.rolling(window).corr(delta_volume)
        # Truong hop A: Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_102_tanh(df, window=70):
        # Tinh TS_STD va TS_MEAN cua close
        std_close = df['close'].rolling(window).std()
        mean_close = df['close'].rolling(window).mean()
        # Tranh chia cho 0
        ratio = std_close / (mean_close + 1e-8)
        # Tinh delta volume
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_volume = volume.diff(1) / (volume + 1e-8)
        # Tinh rolling correlation
        raw = ratio.rolling(window).corr(delta_volume)
        # Truong hop B: Dynamic Tanh
        signal = np.tanh(raw / raw.rolling(window).std())
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_102_zscore(df, window=70):
        # Tinh TS_STD va TS_MEAN cua close
        std_close = df['close'].rolling(window).std()
        mean_close = df['close'].rolling(window).mean()
        # Tranh chia cho 0
        ratio = std_close / (mean_close + 1e-8)
        # Tinh delta volume
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_volume = volume.diff(1) / (volume + 1e-8)
        # Tinh rolling correlation
        raw = ratio.rolling(window).corr(delta_volume)
        # Truong hop C: Rolling Z-Score Clip
        mean_raw = raw.rolling(window).mean()
        std_raw = raw.rolling(window).std()
        signal = ((raw - mean_raw) / std_raw).clip(-1, 1)
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_102_sign(df, window=35):
        # Tinh TS_STD va TS_MEAN cua close
        std_close = df['close'].rolling(window).std()
        mean_close = df['close'].rolling(window).mean()
        # Tranh chia cho 0
        ratio = std_close / (mean_close + 1e-8)
        # Tinh delta volume
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_volume = volume.diff(1) / (volume + 1e-8)
        # Tinh rolling correlation
        raw = ratio.rolling(window).corr(delta_volume)
        # Truong hop D: Sign/Binary Soft
        signal = np.sign(raw)
        signal = pd.Series(signal, index=df.index).fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_102_wf(df, window=100, p1=0.9):
        # Tinh TS_STD va TS_MEAN cua close
        std_close = df['close'].rolling(window).std()
        mean_close = df['close'].rolling(window).mean()
        # Tranh chia cho 0
        ratio = std_close / (mean_close + 1e-8)
        # Tinh delta volume
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_volume = volume.diff(1) / (volume + 1e-8)
        # Tinh rolling correlation
        raw = ratio.rolling(window).corr(delta_volume)
        # Truong hop E: Winsorized Fisher
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        signal = normalized.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_103_rank(df, window=50):
        # Tính return từ close
        close = df['close']
        ret = close.pct_change()
        # Tính TS_MEAN và TS_STD
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std()
        # Tránh chia cho 0
        std_ret = std_ret.replace(0, np.nan)
        # Raw signal: SIGN(mean) * mean / (std + epsilon)
        raw = np.sign(mean_ret) * mean_ret / (std_ret + 1e-8)
        # Chuẩn hóa Rolling Rank về [-1,1]
        raw_rank = raw.rolling(window).rank(pct=True) * 2 - 1
        signal = raw_rank.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_103_tanh(df, window=75):
        close = df['close']
        ret = close.pct_change()
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std()
        std_ret = std_ret.replace(0, np.nan)
        raw = np.sign(mean_ret) * mean_ret / (std_ret + 1e-8)
        # Chuẩn hóa Dynamic Tanh
        raw_std = raw.rolling(window).std()
        raw_std = raw_std.replace(0, np.nan)
        signal = np.tanh(raw / (raw_std + 1e-8))
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_103_zscore(df, window=100):
        close = df['close']
        ret = close.pct_change()
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std()
        std_ret = std_ret.replace(0, np.nan)
        raw = np.sign(mean_ret) * mean_ret / (std_ret + 1e-8)
        # Rolling Z-Score rồi clip
        raw_mean = raw.rolling(window).mean()
        raw_std = raw.rolling(window).std()
        raw_std = raw_std.replace(0, np.nan)
        signal = ((raw - raw_mean) / (raw_std + 1e-8)).clip(-1, 1)
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_103_sign(df, window=65):
        close = df['close']
