    @staticmethod
    def alpha_quanta_randomizer_111_rank(df, window=55):
        ret = df['close'].pct_change()
        ts_mean_ret = ret.rolling(3).mean()
        corr = df['close'].rolling(window).corr(df['matchingVolume'])
        delta_corr = corr.diff(5)
        raw = -ts_mean_ret * np.sign(delta_corr)
        rank = raw.rolling(window).rank(pct=True) * 2 - 1
        return -rank.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_111_tanh(df, window=50):
        ret = df['close'].pct_change()
        ts_mean_ret = ret.rolling(3).mean()
        corr = df['close'].rolling(window).corr(df['matchingVolume'])
        delta_corr = corr.diff(5)
        raw = -ts_mean_ret * np.sign(delta_corr)
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan)).fillna(0)
        return -normalized

    @staticmethod
    def alpha_quanta_randomizer_111_zscore(df, window=50):
        ret = df['close'].pct_change()
        ts_mean_ret = ret.rolling(3).mean()
        corr = df['close'].rolling(window).corr(df['matchingVolume'])
        delta_corr = corr.diff(5)
        raw = -ts_mean_ret * np.sign(delta_corr)
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std().replace(0, np.nan)
        zscore = (raw - mean) / std
        return -zscore.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_111_sign(df, window=75):
        ret = df['close'].pct_change()
        ts_mean_ret = ret.rolling(3).mean()
        corr = df['close'].rolling(window).corr(df['matchingVolume'])
        delta_corr = corr.diff(5)
