    @staticmethod
    def alpha_quanta_randomizer_111_wf(df, window=50):
        ret = df['close'].pct_change()
        ts_mean_ret = ret.rolling(3).mean()
        corr = df['close'].rolling(window).corr(df['matchingVolume'])
        delta_corr = corr.diff(5)
        raw = -ts_mean_ret * np.sign(delta_corr)
        p1 = 0.05
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_112_rank(df, window=75):
        # Tính return -= percent change of close
        close = df['close']
        ret = close.pct_change()
        # TS_MEAN($return, 3) = rolling mean of return over 3 periods
        mean_ret = ret.rolling(3).mean()
        # TS_PCTCHANGE($volume, 5) = percent change of volume over 5 periods
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_pct = volume.pct_change(5)
        # Biểu thức: -TS_MEAN($return, 3) * TS_PCTCHANGE($volume, 5)
        raw = -mean_ret * vol_pct
        # Rolling Rank (A) normalized to [-1, 1]
        ranked = raw.rolling(window).rank(pct=True) * 2 - 1
        signal = ranked.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_112_tanh(df, window=100):
        # Tính return -= percent change of close
        close = df['close']
        ret = close.pct_change()
        # TS_MEAN($return, 3)
        mean_ret = ret.rolling(3).mean()
        # TS_PCTCHANGE($volume, 5)
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_pct = volume.pct_change(5)
        # raw = -mean_ret * vol_pct
        raw = -mean_ret * vol_pct
        # Dynamic Tanh (B): preserve magnitude
        std_val = raw.rolling(window).std().replace(0, 1e-9)
        signal = np.tanh(raw / std_val)
        signal = signal.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_112_zscore(df, window=95):
        # Tính return
        close = df['close']
        ret = close.pct_change()
        mean_ret = ret.rolling(3).mean()
        # Volume pct change
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_pct = volume.pct_change(5)
        # raw = -mean_ret * vol_pct
        raw = -mean_ret * vol_pct
        # Rolling Z-score / Clip (C): for spread/oscillator
        roll_mean = raw.rolling(window).mean()
        roll_std = raw.rolling(window).std().replace(0, 1e-9)
        z_score = (raw - roll_mean) / roll_std
        signal = z_score.clip(-1, 1)
        signal = signal.fillna(0)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_112_sign(df):
        # Tính return
        close = df['close']
        ret = close.pct_change()
        mean_ret = ret.rolling(3).mean()
        # Volume pct change
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_pct = volume.pct_change(5)
        # raw = -mean_ret * vol_pct
        raw = -mean_ret * vol_pct
        # Sign (D): binary direction
        signal = np.sign(raw).fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_112_wf(df, window_rank=80, quantile=0.9):
        # Tính return
        close = df['close']
        ret = close.pct_change()
        mean_ret = ret.rolling(3).mean()
        # Volume pct change
        volume = df.get('matchingVolume', df.get('volume', 1))
        vol_pct = volume.pct_change(5)
        # raw = -mean_ret * vol_pct
        raw = -mean_ret * vol_pct
        # Winsorized Fisher (E): for heavy tails
        p1 = quantile
        p2 = window_rank
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher transform (handle division by zero/constant)
        denom = (high - low) + 1e-9
        normalized_input = ((winsorized - low) / denom) * 1.98 - 0.99
        # Clip to avoid arctanh domain error at ±1
        normalized_input = normalized_input.clip(-0.9999, 0.9999)
        signal = np.arctanh(normalized_input)
        signal = signal.fillna(0)
        return -signal

