    @staticmethod
    def alpha_quanta_randomizer_116_rank(df, window=65):
        returns = df['close'].pct_change().replace([np.inf, -np.inf], 0)
        ts_sum_ret = returns.rolling(5).sum()
        ts_std_ret = returns.rolling(10).std(ddof=0) + 1e-8
        ratio = ts_sum_ret / ts_std_ret
        zscore_ratio = (ratio - ratio.rolling(window).mean()) / ratio.rolling(window).std()
        ts_corr_close_vol = df['close'].rolling(90).corr(df['matchingVolume'])
        ts_corr_close_vol_rank = ts_corr_close_vol.rank(pct=True)
        ts_rank_close = df['close'].rolling(20).rank(pct=True)
        ts_mean_rank = ts_rank_close.rolling(90).mean()
        raw_signal = zscore_ratio - ts_corr_close_vol_rank * ts_mean_rank
        normalized = (raw_signal.rolling(window).rank(pct=True) * 2) - 1
        normalized = normalized.ffill().fillna(0)
        return normalized

