        vol_ma = volume.rolling(window).mean() + 1e-8
        ret_std = ret.rolling(window).std() + 1e-8
        raw = (high - low) / (vol_ma * ret_std)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -signal.fillna(0)

