    @staticmethod
    def alpha_quanta_randomizer_122_k(df, window=30):
        ret = df['close'].pct_change()
        ts_std = ret.rolling(window).std()
        ts_mad = (ret - ret.rolling(window).median()).abs().rolling(window).mean()
        ts_median = ret.rolling(window).median()
        raw = ts_std / (ts_mad + 1e-8 + ts_median ** 2)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

