    @staticmethod
    def alpha_quanta_randomizer_123_wf(df, window=50, quantile=0.1):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_close = close.diff(5).fillna(0)
        sign_delta = pd.Series(np.sign(delta_close), index=df.index)
        ts_mean_vol = volume.rolling(5).mean().fillna(method='ffill').fillna(0)
        ret = close.pct_change().fillna(0)
        ts_std_ret = ret.rolling(5).std().fillna(method='ffill').replace(0, np.nan).fillna(1)
        raw = sign_delta * ts_mean_vol / (ts_std_ret + 1e-8)
        # Normalize with Winsorized Fisher (Case E)
        low = raw.rolling(window).quantile(quantile).fillna(method='ffill').fillna(raw.min())
        high = raw.rolling(window).quantile(1 - quantile).fillna(method='ffill').fillna(raw.max())
        winsorized = raw.clip(lower=low, upper=high)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_124_rank(df, window=100):
        close = df['close']
        volume = df['matchingVolume']
        vol_std = volume.rolling(window).std().replace(0, np.nan)
        ts_mean_close = close.rolling(window).mean()
        ts_mean_close_delay = ts_mean_close.shift(1)
        sign_ts = np.sign(ts_mean_close - ts_mean_close_delay)
        corr_close_vol = close.rolling(window).corr(volume).fillna(0)
        raw = sign_ts * corr_close_vol / (vol_std + 1e-8)
        raw = raw.rank().fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -normalized.fillna(0)

