    @staticmethod
    def alpha_quanta_randomizer_128_rank(df, window=15):
        close = df['close']
        volume = df['matchingVolume']
        returns = close.pct_change().fillna(0)
        positive_volume = volume.where(returns > 0, 0)
        negative_volume = volume.where(returns < 0, 0)
        skew_pos = positive_volume.rolling(window).skew()
        skew_neg = negative_volume.rolling(window).skew()
        volume_std = volume.rolling(window).std().replace(0, np.nan)
        raw = (skew_pos - skew_neg) / volume_std
        # Normalized using rolling rank
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return -result.ffill().fillna(0)

