    @staticmethod
    def alpha_quanta_randomizer_134_wf(df, window=80, p1=0.9):
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        delta_close = close.diff(1)
        ret = delta_close / close
        vol_mean = volume.rolling(window).mean()
        vol_std = volume.rolling(window).std()
        vol_z = (volume - vol_mean) / (vol_std + 1e-8)
        ret_mean = ret.rolling(window).mean()
        vol_z_mean = vol_z.rolling(window).mean()
        cov = ((ret - ret_mean) * (vol_z - vol_z_mean)).rolling(window).sum()
        var_ret = ((ret - ret_mean) ** 2).rolling(window).sum()
        var_vol = ((vol_z - vol_z_mean) ** 2).rolling(window).sum()
        ts_corr = cov / (np.sqrt(var_ret * var_vol).replace(0, np.nan) + 1e-8)
        vol_delay = volume.shift(63)
        sign_val = np.sign(volume / vol_delay - 1)
        raw = ts_corr * sign_val
        # Winsorized Fisher transform
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return -normalized.fillna(0)

