    @staticmethod
    def alpha_quanta_randomizer_136_rank(df, window=10):
        ret = df['close'].pct_change()
        raw = np.sign(ret.rolling(5).mean()) * (ret.rolling(window).mean() / (ret.rolling(window).std() + 1e-8)) * ret.rolling(60).corr(df.get('matchingVolume', df.get('volume', 1)).iloc[:, 0] if isinstance(df.get('matchingVolume', df.get('volume', 1)), pd.DataFrame) else df.get('matchingVolume', df.get('volume', 1)))
        return (raw.rolling(window).rank(pct=True) * 2 - 1).fillna(0)

