        vol_ret = np.log1p(vol_ret)
        corr = ret.rolling(window).corr(vol_ret).fillna(0)
        corr_abs = corr.abs()
        std_ret = ret.rolling(window).std().fillna(0)
        denom = std_ret + 1e-8
        raw = corr_abs / denom
