    @staticmethod
    def alpha_quanta_randomizer_158_rank(df, window=10, return_window=30):
        close = df['close']
        volume = df.get('volume', df['matchingVolume'])
        returns = close.pct_change()
        corr = close.rolling(window).corr(volume)
        max_corr = corr.clip(lower=0)
        mean_ret = returns.rolling(return_window).mean()
        std_ret = returns.rolling(return_window).std().replace(0, np.nan)
        raw = max_corr * mean_ret / (std_ret + 1e-8)
        rank = raw.rolling(window * 3).rank(pct=True) * 2 - 1
        return rank.fillna(0)

