    @staticmethod
    def alpha_quanta_randomizer_160_wf(df, window=60, sub_window=7):
        close = df['close']
        raw = close / (close.rolling(window).mean() + 1e-8)
        zscore = (raw - raw.rolling(window).mean()) / raw.rolling(window).std()
        cond = zscore < -1.5
        delta = close.diff(1)
        sign_delta = np.sign(delta)
        combined = np.where(cond, sign_delta, 0)
        series = pd.Series(combined, index=df.index)
        p1 = 0.05
        p2 = sub_window
        low = series.rolling(p2).quantile(p1)
        high = series.rolling(p2).quantile(1 - p1)
        winsorized = series.clip(lower=low, upper=high, axis=0)
        span = high - low + 1e-9
        scaled = ((winsorized - low) / span) * 1.98 - 0.99
        scaled = scaled.clip(-0.99, 0.99)
        normalized = np.arctanh(scaled)
        return normalized

    @staticmethod
    def alpha_quanta_randomizer_161_rank(df, window=25):
        # Tính return đơn giản
        ret = df['close'].pct_change().fillna(0)
        # Rolling mean và std
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std().replace(0, np.nan)
        # Z-score raw
        raw = (ret - mean_ret) / std_ret
        # Chuẩn hóa Rolling Rank (A) - loại bỏ nhiễu, đưa về phân phối đều
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_161_tanh(df, window=30):
        ret = df['close'].pct_change().fillna(0)
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std().replace(0, np.nan)
        raw = (ret - mean_ret) / std_ret
        # Dynamic Tanh (B) - giữ cường độ, giới hạn về [-1,1]
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_161_zscore(df, window=60):
        ret = df['close'].pct_change().fillna(0)
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std().replace(0, np.nan)
        raw = (ret - mean_ret) / std_ret
        # Rolling Z-Score/Clip (C) - giữ nguyên dạng oscillator
        normalized = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std().replace(0, np.nan)).clip(-1, 1)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_161_sign(df, window=60):
        ret = df['close'].pct_change().fillna(0)
        mean_ret = ret.rolling(window).mean()
        std_ret = ret.rolling(window).std().replace(0, np.nan)
        raw = (ret - mean_ret) / std_ret
        # Sign/Binary Soft (D) - chỉ lấy dấu tín hiệu
        normalized = np.sign(raw)
        return pd.Series(normalized, index=df.index).fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_161_wf(df, p1=0.1, p2=70):
        ret = df['close'].pct_change().fillna(0)
        mean_ret = ret.rolling(p2).mean()
        std_ret = ret.rolling(p2).std().replace(0, np.nan)
        raw = (ret - mean_ret) / std_ret
        # Winsorized Fisher (E) - xử lý đuôi nặng, ngoại lệ
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher Transform đưa về [-1,1]
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

