    @staticmethod
    def alpha_quanta_randomizer_166_k(df, window=40, sub_window=3):
        # Xây dựng biến thời gian x = [0,1,2,3,4]
        x = pd.Series(np.arange(len(df)), index=df.index)
        y = df['close']
        # Tính slope: rolling covariance / rolling variance (window=sub_window)
        cov = y.rolling(sub_window).cov(x)
        var_x = x.rolling(sub_window).var().replace(0, np.nan)
        slope = cov / var_x
        # Slope sign (1 or -1)
        slope_sign = pd.Series(np.sign(slope), index=df.index)
        # Tính (open - low) / open
        open_minus_low = (df['open'] - df['low']) / (df['open'] + 1e-8)
        # Tính volatility ratio: TS_STD(close,5) / TS_MEAN(close,5)
        vol_ratio = df['close'].rolling(sub_window).std() / (df['close'].rolling(sub_window).mean() + 1e-8)
        # Kết hợp
        raw = slope_sign * open_minus_low / (vol_ratio + 1e-8)
        # Chuẩn hóa Rolling Rank
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

