        low = df['low']
        raw = (close - open_).abs() / (high - low + 1e-8)
        sign_open_close = np.sign(open_ - close)
        delta_close = close.diff(10)
        ts_mean_delta = delta_close.rolling(window=10).mean()
        sign_delta = np.sign(delta_close - ts_mean_delta)
        raw_signal = raw * sign_open_close * sign_delta
        normalized = ((raw_signal - raw_signal.rolling(window=window).mean()) / raw_signal.rolling(window=window).std()).clip(-1, 1)
        return normalized.fillna(0)

