    @staticmethod
    def alpha_quanta_randomizer_174_tanh(df, window=65):
        hilo = df['high'] - df['low']
        volume = df.get('matchingVolume', df.get('volume', 1))
        rolling_cov = hilo.rolling(window).cov(volume)
        rolling_var_hilo = hilo.rolling(window).var().replace(0, np.nan)
