    @staticmethod
    def alpha_quanta_randomizer_191_wf(df, p1=0.1, p2=10):
        low_5_min_total = df['low'].rolling(p2, min_periods=1).min()
        high_5_max = df['high'].rolling(p2, min_periods=1).max()
        raw = (df['close'] - low_5_min_total) / (high_5_max - low_5_min_total + 1e-8)
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

