    @staticmethod
    def alpha_quanta_randomizer_195_rank(df, window=55):
        close = df['close']
        high = df['high']
        low = df['low']
        volume = df['matchingVolume']
        n = len(df)
        # REGRESSI using slope formula
        days = pd.Series(np.arange(n), index=df.index)
        slope = close.rolling(window).cov(days) / days.rolling(window).var().replace(0, np.nan)
        std_slope = slope.rolling(window).std()
        # TS_STD of REGRESSI
        std_reg = slope.rolling(window).std()
        term1 = -std_reg
        # COUNT(volume > delay(volume,1), 5)/5
        vol_delay = volume.shift(1)
        vol_up_indicator = (volume > vol_delay).astype(float)
        count_vol_up = vol_up_indicator.rolling(5).sum()
        term2 = count_vol_up / 5.0
        # (close - TS_MIN(low,5)) / (TS_MAX(high,5) - TS_MIN(low,5) + 1e-8)
        min_low5 = low.rolling(5).min()
        max_high5 = high.rolling(5).max()
        term3 = (close - min_low5) / (max_high5 - min_low5 + 1e-8)
        # (1 - ABS(TS_ZSCORE(TRANGE, 20)))
        # TRANGE = max(high-low, max(abs(high - delay(close,1)), abs(low - delay(close,1))))
        close_delay1 = close.shift(1)
        tr1 = high - low
        tr2 = abs(high - close_delay1)
        tr3 = abs(low - close_delay1)
        trange = pd.concat([tr1, tr2, tr3], axis=1).max(axis=1)
        mean_tr = trange.rolling(20).mean()
        std_tr = trange.rolling(20).std().replace(0, np.nan)
        zscore_tr = (trange - mean_tr) / (std_tr + 1e-9)
        term4 = 1 - abs(zscore_tr)
        raw = (term1 + term2 + term3) * term4
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

