    @staticmethod
    def alpha_quanta_randomizer_198_wf(df, window=20, sub_window=20, p1=0.05):
        vol = df['volume'].clip(lower=1)
        log_vol = np.log(vol)
        low_lv = log_vol.rolling(sub_window).quantile(p1)
        high_lv = log_vol.rolling(sub_window).quantile(1 - p1)
        winsorized_lv = log_vol.clip(lower=low_lv, upper=high_lv, axis=0)
        fisher_lv = np.arctanh(((winsorized_lv - low_lv) / (high_lv - low_lv + 1e-9)) * 1.98 - 0.99)
        fisher_lv = fisher_lv.fillna(0)

        delay_close = df['close'].shift(1)
        true_range = pd.concat([
            df['high'] - df['low'],
            (df['high'] - delay_close).abs(),
            (df['low'] - delay_close).abs()
        ], axis=1).max(axis=1)
        divisor = df['close'] * vol + 1e-12
        raw_inner = true_range / divisor
        mean_inner = raw_inner.rolling(5).mean()
        low_inner = mean_inner.rolling(sub_window).quantile(p1)
        high_inner = mean_inner.rolling(sub_window).quantile(1 - p1)
        winsorized_inner = mean_inner.clip(lower=low_inner, upper=high_inner, axis=0)
        fisher_inner = np.arctanh(((winsorized_inner - low_inner) / (high_inner - low_inner + 1e-9)) * 1.98 - 0.99)
        fisher_inner = fisher_inner.fillna(0)

        result = fisher_lv - fisher_inner
        return result.clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_199_rank(df, window=70):
        close = df['close']
        open = df['open']
        volume = df.get('matchingVolume', df.get('volume', 1))
        log_cv = np.log(close * volume + 1)
        ts_z_log = (log_cv - log_cv.rolling(window=window).mean()) / log_cv.rolling(window=window).std().replace(0, np.nan)
        delay_close = close.shift(1).fillna(0)
        ratio = open / (delay_close + 1e-12) - 1
        abs_ratio = np.abs(ratio)
        denom = close * volume + 1e-12
        raw_inner = abs_ratio / denom
        ts_mean_inner = raw_inner.rolling(window=5).mean()
        ts_z_inner = (ts_mean_inner - ts_mean_inner.rolling(window=window).mean()) / ts_mean_inner.rolling(window=window).std().replace(0, np.nan)
        raw = ts_z_log - ts_z_inner
        result = (raw.rolling(window=window).rank(pct=True) * 2) - 1
        return -result.fillna(0)

