    @staticmethod
    def alpha_quanta_randomizer_199_wf(df, window=10, p1=0.5):
        close = df['close']
        open = df['open']
        volume = df.get('matchingVolume', df.get('volume', 1))
        log_cv = np.log(close * volume + 1)
        ts_z_log = (log_cv - log_cv.rolling(window=window).mean()) / log_cv.rolling(window=window).std().replace(0, np.nan)
        delay_close = close.shift(1).fillna(0)
        ratio = open / (delay_close + 1e-12) - 1
        abs_ratio = np.abs(ratio)
        denom = close * volume + 1e-12
        raw_inner = abs_ratio / denom
        ts_mean_inner = raw_inner.rolling(window=5).mean()
        ts_z_inner = (ts_mean_inner - ts_mean_inner.rolling(window=window).mean()) / ts_mean_inner.rolling(window=window).std().replace(0, np.nan)
        raw = ts_z_log - ts_z_inner
        p2 = window * 2
        low = raw.rolling(window=p2).quantile(p1)
        high = raw.rolling(window=p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        numerator = (winsorized - low) / (high - low + 1e-9)
        normalized = np.arctanh(numerator * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_200_rank(df, window=20):
        vwap = df.get('vwap', (df['high'] + df['low'] + df['close']) / 3)
        ret = df['close'].pct_change().replace([np.inf, -np.inf], np.nan)
        vol_log = np.log1p(df['matchingVolume'])
        vol_mean = df['matchingVolume'].rolling(window=5).mean()
        vol_adj = df['matchingVolume'] / vol_mean.replace(0, np.nan)
        volume_impact = np.where(vol_adj > 1, ret, -ret)
        raw = (vol_log - vol_log.rolling(window).mean()) / vol_log.rolling(window).std() - (np.abs(ret) / (df['matchingVolume'] + 1e-12)).rolling(window=5).mean()
        raw = raw.rolling(window=5).mean() - raw
        raw = raw - volume_impact.rolling(window=5).mean()
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(method='ffill').fillna(0.0)

