    @staticmethod
    def alpha_quanta_randomizer_202_wf(df, window=70, p1=0.7):
        p2 = window
        close = df['close']
        days = pd.Series(np.arange(len(df)), index=df.index)
        log_close = np.log(close)
        cov = log_close.rolling(window).cov(days)
        var_x = days.rolling(window).var().replace(0, np.nan)
        regbeta = cov / var_x
        seq = np.arange(1, window + 1)
        regbeta_seq = regbeta.rolling(window).apply(lambda x: (x * seq[:len(x)]).sum(), raw=True) / window
        ts_var_reg = ((regbeta_seq - regbeta_seq.rolling(window).mean())**2).rolling(window).mean()
        ts_var_log = ((log_close - log_close.rolling(window).mean())**2).rolling(window).mean() + 1e-8
        raw = ts_var_reg / ts_var_log
        # Winsorized Fisher
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        # Fisher Transform
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        # Handle inf from arctanh
        normalized = normalized.replace([np.inf, -np.inf], np.nan).clip(-1, 1)
        return -normalized.fillna(0)

