    @staticmethod
    def alpha_quanta_randomizer_204_k(df, window_short=5, window_long=60):
        high = df['high'].values
        low = df['low'].values
        volume = df.get('matchingVolume', df.get('volume', 1)).values
        close = df['close'].values
        hl_ratio = np.log(high / (low + 1e-8))
        pow_hl = hl_ratio ** 2
        returns = close / np.concatenate(([close[0]], close[:-1])) - 1
        log_vol = np.log1p(volume)
        series_short = pd.Series(1 / (pd.Series(pow_hl).rolling(window_short).mean() + 1e-8), index=df.index)
        series_long = pd.Series(pd.Series(pow_hl).rolling(window_long).mean(), index=df.index) + 1e-8
        factor1 = -series_short / series_long
        factor1_rank = factor1.rolling(window_short).rank(pct=True) * 2 - 1
        pow_hl_series = pd.Series(pow_hl, index=df.index)
        std_pow = pow_hl_series.rolling(20).std()
        factor2 = -std_pow
        factor2_rank = factor2.rolling(20).rank(pct=True) * 2 - 1
        log_vol_series = pd.Series(log_vol, index=df.index)
        zscore_vol = (log_vol_series - log_vol_series.rolling(20).mean()) / log_vol_series.rolling(20).std().replace(0, np.nan)
        factor3 = -zscore_vol
        factor3_rank = factor3.rolling(20).rank(pct=True) * 2 - 1
        abs_ret_series = pd.Series(np.abs(returns), index=df.index)
        log_vol_safe = pd.Series(log_vol, index=df.index) + 1e-6
        ratio_ret_vol = abs_ret_series / log_vol_safe
        mean_ratio = ratio_ret_vol.rolling(5).mean()
        factor4 = -mean_ratio
        factor4_rank = factor4.rolling(5).rank(pct=True) * 2 - 1
        signal = factor1_rank.fillna(0) + factor2_rank.fillna(0) + factor3_rank.fillna(0) + factor4_rank.fillna(0)
        return signal.ffill().fillna(0)

