    @staticmethod
    def alpha_quanta_randomizer_205_rank(df, window=30):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df['matchingVolume']
        log_hl = np.log(high / (low + 1e-8))
        pow_hl = np.power(log_hl, 2)
        mean10 = pow_hl.rolling(window).mean()
        mean60 = pow_hl.rolling(60).mean()
        ratio = mean10 / (mean60 + 1e-8)
        std20 = pow_hl.rolling(20).std()
        log_vol = np.log(volume + 1)
        zscore_vol = (log_vol - log_vol.rolling(20).mean()) / log_vol.rolling(20).std()
        hl_range = 2 * close - high - low
        hl_diff = high - low + 1e-6
        ratio2 = hl_range / hl_diff
        mean5 = ratio2.rolling(5).mean()
        raw = ratio.rank() * std20.rank() * zscore_vol.rank() * mean5.rank()
        param = max(10, window // 2)
        norm = (raw.rolling(param).rank(pct=True) * 2) - 1
        return norm

