        return_raw = -np.sign(ret) * (true_range / (mean_true_range + 1e-8)) * (1 - np.abs((2 * close - high - low) / (high - low + 1e-8))) * (1 - np.abs(ret.rolling(window=window).sum()) / window)
        standardized = return_raw.rolling(rank_window).rank(pct=True) * 2 - 1
        return -standardized.fillna(0)

