        abs_close_open = (close / open_price - 1).abs()
        true_range = (high - low).clip(0, None)
        hc_diff = (high - delay_close).abs()
        lc_diff = (low - delay_close).abs()
        max_hc_lc = pd.concat([hc_diff, lc_diff], axis=1).max(axis=1)
        atr = pd.concat([true_range, max_hc_lc], axis=1).max(axis=1)
