        denominator = (high - low) + 1e-8
        inner_fraction = 1 - (numerator / denominator).abs()
        raw = -sign_term * abs_close_open * atr_norm * inner_fraction
        signal = raw.rolling(window).rank(pct=True) * 2 - 1
        return -signal

