    @staticmethod
    def alpha_quanta_randomizer_212_rank(df, window=5):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = df['close'].pct_change(fill_method=None).fillna(0)
        range_val = high - low
        range_ma = range_val.rolling(window=window).mean()
        factor1 = (range_val / (range_ma + 1e-8))
        mid = 0.5 * (high + low)
        inner = (-abs(close - mid)) / (range_val + 1e-8)
        rank_inner = inner.rolling(window).rank(pct=True)
        factor2 = rank_inner * (-1)
        term1 = factor1 + factor2
        ret_sq = ret * ret
        vol10 = (ret_sq.rolling(10).mean() + 1e-8).apply(np.sqrt)
        vol60 = (ret_sq.rolling(60).mean() + 1e-8).apply(np.sqrt)
        part = 1 - vol10 / vol60
        vol_ratio = volume / (volume.rolling(20).mean() + 1e-8)
        sign_ret = np.sign(ret)
        rank_vol = (vol_ratio * sign_ret).rolling(20).rank(pct=True)
        term2 = part * rank_vol
        raw = term1 + term2
        raw = raw.replace([np.inf, -np.inf], 0).fillna(0)
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized

