        sign_direction = (close - open_).apply(np.sign)
        raw = -rank_ret_vol * rank_spread * sign_direction
        normalized = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        normalized = normalized.fillna(0)
