    @staticmethod
    def alpha_quanta_randomizer_216_wf(df, window=60, p1=0.3):
        high = df['high']
        low = df['low']
        close = df['close']
        open_ = df['open']
        volume = df['matchingVolume']
        ret = close.pct_change()
        abs_ret = ret.abs()
