        rank_ret_vol = ret_vol_ratio.rolling(window).rank(pct=True)
        range_hl = high - low
        avg_range_hl = range_hl.rolling(window).mean() + 1e-8
        range_ratio = range_hl / avg_range_hl
        body = (close - open_).abs()
        max_body = (high - low).clip(lower=1e-8)
        body_ratio = body / max_body
        spread_factor = range_ratio * (1 - body_ratio)
        rank_spread = spread_factor.rolling(window).rank(pct=True)
        sign_direction = (close - open_).apply(np.sign)
