    @staticmethod
    def alpha_quanta_randomizer_217_rank(df, window=100):
        close = df['close'].values
        volume = df.get('matchingVolume', df.get('volume', 1))
        ret = pd.Series(np.diff(close, prepend=close[0]) / close, index=df.index)
