        vol_ratio = df['matchingVolume'].rolling(window).mean() / (df['matchingVolume'].rolling(sub_window).mean() + 1e-8)
        vol_rank = vol_ratio.rolling(window).rank(pct=True) * 2 - 1
        ret = df['close'].pct_change()
        ret_sum = ret.rolling(10).sum()
        ret_rank = ret_sum.rolling(window).rank(pct=True) * 2 - 1
        signal = -vol_rank * ret_rank
        return -signal.fillna(0)

