        skew1 = pos_ret_sum.rolling(10).skew()
        skew2 = neg_ret_sum.rolling(10).skew()
        raw = skew1 - skew2
        rank_raw = (raw.rolling(window).rank(pct=True) * 2) - 1
        sign = np.sign(ret.rolling(5).sum())
        signal = rank_raw * sign
        signal = signal.ffill().fillna(0)
        return signal.clip(-1, 1)

