        ratio = ret_std / (ret_mean + 1e-8)
        ratio_rank = ratio.rank(pct=True) * 2 - 1
        raw = ts_corr + zscore_norm - ratio_rank
        norm = raw.rolling(window).rank(pct=True) * 2 - 1
        return -norm

