    @staticmethod
    def alpha_quanta_randomizer_228_rank(df, window=10, sub_window=7):
        close = df['close']
        volume = df.get('volume', df.get('matchingVolume', pd.Series(0, index=df.index))).fillna(0)
        ret = df['close'].pct_change()
        ret_pos_sum = ret.rolling(window).apply(lambda x: x[x > 0].sum(), raw=True)
        ret_neg_sum = ret.rolling(window).apply(lambda x: x[x < 0].sum(), raw=True)
        skew_pos = ret_pos_sum.rolling(window).skew()
        skew_neg = ret_neg_sum.rolling(window).skew()
        numerator = (skew_pos - skew_neg) / (ret.rolling(10).std() + 1e-8)
        # Rolling rank normalization A
        signal = (numerator.rolling(window).rank(pct=True) * 2) - 1
        # Second factor: rank of correlation
        corr = close.rolling(sub_window).corr(volume)
        corr_rank = (corr.rolling(sub_window).rank(pct=True) * 2) - 1
        # Third factor: sign of mean return
        mean_ret = ret.rolling(sub_window).mean()
        sign_mean = np.sign(mean_ret)
        # Combine
        result = signal * corr_rank * sign_mean
        return result.fillna(0)

