    @staticmethod
    def alpha_quanta_randomizer_234_k(df, window=100):
        returns = df['close'].pct_change()
        mean = returns.rolling(window).mean()
        std = returns.rolling(window).std().replace(0, np.nan)
        zscore = (returns - mean) / std
        delayed_zscore = zscore.shift(1)
        mean_ret = returns.rolling(window).mean()
        raw = delayed_zscore * mean_ret
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0)
        return signal

