    @staticmethod
    def alpha_quanta_randomizer_235_rank(df, window=60, delay=2):
        ret = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        # Use np.log1p for volume if needed, but here we keep raw as per RANK context
        # TS_CORR between return and volume
        corr = ret.rolling(window).corr(vol)
        # Delay the correlation by 'delay' periods
        corr_delayed = corr.shift(delay)
        # RANK of (corr - delayed_corr)
        raw = corr - corr_delayed
        # Rolling Rank normalization
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return norm.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_235_tanh(df, window=50, delay=1):
        ret = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        corr = ret.rolling(window).corr(vol)
        corr_delayed = corr.shift(delay)
        raw = corr - corr_delayed
        # Dynamic Tanh normalization
        norm = np.tanh(raw / raw.rolling(window).std().replace(0, np.nan))
        return norm.fillna(0).clip(-1, 1)

    @staticmethod
    def alpha_quanta_randomizer_235_zscore(df, window=50, delay=1):
        ret = df['close'].pct_change()
        vol = df.get('matchingVolume', df.get('volume', 1))
        corr = ret.rolling(window).corr(vol)
        corr_delayed = corr.shift(delay)
        raw = corr - corr_delayed
        # Rolling Z-Score/Clip normalization
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std().replace(0, np.nan)
        norm = ((raw - mean) / std).clip(-1, 1)
        return norm.fillna(0).clip(-1, 1)

