    @staticmethod
    def alpha_quanta_randomizer_238_wf(df, window=30, p1=0.1, p2=60):
        delta_close = df['close'].diff(1)
        mean_delta = delta_close.rolling(window).mean()
        vol = df.get('matchingVolume', df.get('volume', 1))
        raw = np.sign(mean_delta) * vol.rolling(window).std() / (vol.rolling(window).mean() + 1e-8)
        winsorized_window = p2
        low = raw.rolling(winsorized_window).quantile(p1)
        high = raw.rolling(winsorized_window).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized

