        high = df['high']
        low = df['low']
        open_ = df['open']
        seq = pd.Series(np.arange(len(df)), index=df.index)
        corr = close.rolling(window).corr(seq)
        corr2 = corr ** 2
        hl_div = (high - low) / (open_ + 1e-8)
        inv_denom = 1.0 / (hl_div + 1)
        raw = corr2 * inv_denom
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

