    @staticmethod
    def alpha_quanta_randomizer_245_rank(trailing_rank: int = 40):
        high_ = df['high']
        low_ = df['low']
        open_ = df['open']
        close_ = df['close']
        volume_ = df.get('matchingVolume', df.get('volume', 1))

        # TS_CORR($close, SEQUENCE(10), 10)
        sequence = pd.Series(np.arange(1, 11), index=df.index[-10:]).reindex(df.index)
        seq_10 = pd.Series(np.tile(np.arange(10), len(df) // 10 + 1)[:len(df)], index=df.index)
        seq_valid = seq_10.replace({0: np.nan}).ffill()
        close_roll_10 = closest_ = close_.rolling(10, min_periods=1).mean()
        cov_close_seq = closest_.rolling(10, min_periods=9).cov(seq_valid)
        var_seq = seq_valid.rolling(10, min_periods=9).var().replace(0, np.nan)
        ts_corr_val = (cov_close_seq / (close_.rolling(10, min_periods=9).std() * np.sqrt(var_seq)))
        raw_a = (ts_corr_val ** 2) * (1 / ((high_ - low_) / (open_ + 1e-8) + 1)) * (1 / (close_.rolling(5, min_periods=4).std() * volume_.rolling(5, min_periods=4).mean() + 1))

        # Rolling Rank (A)
        result = (raw_a.rolling(trailing_rank, min_periods=2).rank(pct=True) * 2) - 1
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_245_tanh(window: int = 40):
        high_ = df['high']
        low_ = df['low']
        open_ = df['open']
        close_ = df['close']
        volume_ = df.get('matchingVolume', df.get('volume', 1))

        sequence = pd.Series(np.tile(np.arange(10), len(df) // 10 + 1)[:len(df)], index=df.index).replace({0: np.nan}).ffill()
        cov_close_seq = close_.rolling(10, min_periods=9).cov(sequence)
        var_seq = sequence.rolling(10, min_periods=9).var().replace(0, np.nan)
        ts_corr_val = (cov_close_seq / (close_.rolling(10, min_periods=9).std() * np.sqrt(var_seq)))
        raw_b = (ts_corr_val ** 2) * (1 / ((high_ - low_) / (open_ + 1e-8) + 1)) * (1 / (close_.rolling(5, min_periods=4).std() * volume_.rolling(5, min_periods=4).mean() + 1))

        # Dynamic Tanh (B)
        result = np.tanh(raw_b / (raw_b.rolling(window, min_periods=2).std().replace(0, np.nan)))
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_245_zscore(window: int = 40):
        high_ = df['high']
        low_ = df['low']
        open_ = df['open']
        close_ = df['close']
        volume_ = df.get('matchingVolume', df.get('volume', 1))

        sequence = pd.Series(np.tile(np.arange(10), len(df) // 10 + 1)[:len(df)], index=df.index).replace({0: np.nan}).ffill()
        cov_close_seq = close_.rolling(10, min_periods=9).cov(sequence)
        var_seq = sequence.rolling(10, min_periods=9).var().replace(0, np.nan)
        ts_corr_val = (cov_close_seq / (close_.rolling(10, min_periods=9).std() * np.sqrt(var_seq)))
        raw_c = (ts_corr_val ** 2) * (1 / ((high_ - low_) / (open_ + 1e-8) + 1)) * (1 / (close_.rolling(5, min_periods=4).std() * volume_.rolling(5, min_periods=4).mean() + 1))

        # Rolling Z-Score/Clip (C)
        result = ((raw_c - raw_c.rolling(window, min_periods=2).mean()) / raw_c.rolling(window, min_periods=2).std().replace(0, np.nan)).clip(-1, 1)
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_245_sign(window: int = 20):
        high_ = df['high']
        low_ = df['low']
        open_ = df['open']
        close_ = df['close']
        volume_ = df.get('matchingVolume', df.get('volume', 1))

        sequence = pd.Series(np.tile(np.arange(10), len(df) // 10 + 1)[:len(df)], index=df.index).replace({0: np.nan}).ffill()
        cov_close_seq = close_.rolling(10, min_periods=9).cov(sequence)
        var_seq = sequence.rolling(10, min_periods=9).var().replace(0, np.nan)
        ts_corr_val = (cov_close_seq / (close_.rolling(10, min_periods=9).std() * np.sqrt(var_seq)))
        raw_d = (ts_corr_val ** 2) * (1 / ((high_ - low_) / (open_ + 1e-8) + 1)) * (1 / (close_.rolling(5, min_periods=4).std() * volume_.rolling(5, min_periods=4).mean() + 1))

        # Sign/Binary Soft (D)
        result = np.sign(raw_d) * (raw_d.rolling(window, min_periods=2).mean() / (raw_d.rolling(window, min_periods=2).mean().abs() + 1e-8)).clip(-1, 1)
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_245_wf(p1: float = 0.05, p2: int = 40):
        high_ = df['high']
        low_ = df['low']
        open_ = df['open']
        close_ = df['close']
        volume_ = df.get('matchingVolume', df.get('volume', 1))

        sequence = pd.Series(np.tile(np.arange(10), len(df) // 10 + 1)[:len(df)], index=df.index).replace({0: np.nan}).ffill()
        cov_close_seq = close_.rolling(10, min_periods=9).cov(sequence)
        var_seq = sequence.rolling(10, min_periods=9).var().replace(0, np.nan)
        ts_corr_val = (cov_close_seq / (close_.rolling(10, min_periods=9).std() * np.sqrt(var_seq)))
        raw_e = (ts_corr_val ** 2) * (1 / ((high_ - low_) / (open_ + 1e-8) + 1)) * (1 / (close_.rolling(5, min_periods=4).std() * volume_.rolling(5, min_periods=4).mean() + 1))

        # Winsorized Fisher Transform (E)
        low_bound = raw_e.rolling(p2, min_periods=2).quantile(p1)
        high_bound = raw_e.rolling(p2, min_periods=2).quantile(1 - p1)
        winsorized = raw_e.clip(lower=low_bound, upper=high_bound, axis=0)
        numerator = ((winsorized - low_bound) / (high_bound - low_bound + 1e-9)) * 1.98 - 0.99
        numerator = numerator.clip(-0.99, 0.99)
        result = np.arctanh(numerator)
        result = result.clip(-1, 1)
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_246_rank(df, window=35):
        # Tính toán raw alpha: RANK(TS_STD(high-low, 5) / (TS_STD(close, 5) + 1e-8)) * TS_CORR(volume, close, 3)
        spread = df['high'] - df['low']
        spread_std = spread.rolling(window).std()
        close_std = df['close'].rolling(window).std() + 1e-8
        ratio = spread_std / close_std
        rank_ratio = ratio.rolling(window).rank(pct=True)
        # TS_CORR(volume, close, 3) - điều chỉnh window giống sub_window cho tham số thứ 2
        corr_window = 3
        volume = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        # Tính correlation rolling bằng pandas
        corr = volume.rolling(corr_window).corr(close)
        raw = rank_ratio * corr
        # Chuẩn hóa: Rolling Rank (loại bỏ nhiễu)
        norm = (raw.rolling(window).rank(pct=True) * 2) - 1
        return norm.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_246_tanh(df, window=35):
        spread = df['high'] - df['low']
        spread_std = spread.rolling(window).std()
        close_std = df['close'].rolling(window).std() + 1e-8
        ratio = spread_std / close_std
        rank_ratio = ratio.rolling(window).rank(pct=True)
        corr_window = 3
        volume = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        corr = volume.rolling(corr_window).corr(close)
        raw = rank_ratio * corr
        # Chuẩn hóa: Dynamic Tanh
        norm = np.tanh(raw / (raw.rolling(window).std() + 1e-8))
        return norm.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_246_zscore(df, window=45):
        spread = df['high'] - df['low']
        spread_std = spread.rolling(window).std()
        close_std = df['close'].rolling(window).std() + 1e-8
        ratio = spread_std / close_std
        rank_ratio = ratio.rolling(window).rank(pct=True)
        corr_window = 3
        volume = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        corr = volume.rolling(corr_window).corr(close)
        raw = rank_ratio * corr
        # Chuẩn hóa: Rolling Z-Score/Clip
        mean = raw.rolling(window).mean()
        std = raw.rolling(window).std()
        norm = ((raw - mean) / (std + 1e-8)).clip(-1, 1)
        return norm.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_246_sign(df, window=70):
        spread = df['high'] - df['low']
        spread_std = spread.rolling(window).std()
