    @staticmethod
    def alpha_quanta_randomizer_246_wf(df, window=40, p1=0.1):
        spread = df['high'] - df['low']
        spread_std = spread.rolling(window).std()
        close_std = df['close'].rolling(window).std() + 1e-8
        ratio = spread_std / close_std
        rank_ratio = ratio.rolling(window).rank(pct=True)
        corr_window = 3
        volume = df.get('matchingVolume', df.get('volume', 1))
        close = df['close']
        corr = volume.rolling(corr_window).corr(close)
        raw = rank_ratio * corr
        # Chuẩn hóa: Winsorized Fisher
        p2 = window
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        norm = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return norm.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_247_k(df, window=30):
        # Tính raw: rolling 5-bar close change chia cho rolling 5-bar high-low range std
        close_change = df['close'] - df['close'].shift(1)
        hilo_range = df['high'] - df['low']
        rolling_sum = close_change.rolling(window).sum()
        rolling_std = hilo_range.rolling(window).std()
        raw = rolling_sum / (rolling_std + 1e-8)
        # Rolling Rank normalization (Case A): map to [-1, 1]
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        signal = signal.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_247_h(df, window=20):
        # Tính raw: rolling 5-bar close change chia cho rolling 5-bar high-low range std
        close_change = df['close'] - df['close'].shift(1)
        hilo_range = df['high'] - df['low']
        rolling_sum = close_change.rolling(window).sum()
        rolling_std = hilo_range.rolling(window).std()
        raw = rolling_sum / (rolling_std + 1e-8)
        # Dynamic Tanh normalization (Case B): preserve magnitude, map to [-1, 1]
        signal = np.tanh(raw / raw.rolling(window).std())
        signal = signal.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_247_p(df, window=30):
        # Tính raw: rolling 5-bar close change chia cho rolling 5-bar high-low range std
        close_change = df['close'] - df['close'].shift(1)
        hilo_range = df['high'] - df['low']
        rolling_sum = close_change.rolling(window).sum()
        rolling_std = hilo_range.rolling(window).std()
        raw = rolling_sum / (rolling_std + 1e-8)
        # Rolling Z-Score clip normalization (Case C): map to [-1, 1]
        signal = ((raw - raw.rolling(window).mean()) / raw.rolling(window).std()).clip(-1, 1)
        signal = signal.fillna(0)
        return signal

    @staticmethod
    def alpha_quanta_randomizer_247_n(df, window=20):
        # Tính raw: rolling 5-bar close change chia cho rolling 5-bar high-low range std
        close_change = df['close'] - df['close'].shift(1)
