    @staticmethod
    def alpha_quanta_randomizer_247_r(df, window=20, p1=0.1):
        # Tính raw: rolling 5-bar close change chia cho rolling 5-bar high-low range std
        close_change = df['close'] - df['close'].shift(1)
        hilo_range = df['high'] - df['low']
        rolling_sum = close_change.rolling(window).sum()
        rolling_std = hilo_range.rolling(window).std()
        raw = rolling_sum / (rolling_std + 1e-8)
        # Winsorized Fisher normalization (Case E): map to [-1, 1]
        p2 = window * 5
        p2 = max(p2, 10)
        low = raw.rolling(p2).quantile(p1)
        high = raw.rolling(p2).quantile(1 - p1)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
