    @staticmethod
    def alpha_quanta_randomizer_249_rank(df, window_rank=45):
        close = df['close']
        high = df['high']
        low = df['low']
        delta_close = close.diff(3)
        delay_close = close.shift(3)
        raw = (delta_close / delay_close).abs() * (high - low).rolling(3).std() / ((high - low).rolling(20).mean() + 1e-8)
        signal = (raw.rolling(window_rank).rank(pct=True) * 2) - 1
        signal = signal.fillna(0).replace([np.inf, -np.inf], 0)
        return -signal

