    @staticmethod
    def alpha_quanta_randomizer_250_zscore(df, window=30):
        high = df['high']
        low = df['low']
        close = df['close']
        volume = df.get('matchingVolume', df.get('volume', 1))
        price_diff = high - low
        rs_period = 5
        delta = close.diff()
        gain = delta.clip(lower=0)
        loss = (-delta).clip(lower=0)
        avg_gain = gain.rolling(rs_period).mean()
        avg_loss = loss.rolling(rs_period).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        rsi = 100 - (100 / (1 + rs))
        rsi = rsi.fillna(50)
        raw_rsi = (50 - rsi)
        corr_hl_vol = price_diff.rolling(rs_period).corr(volume)
        mean_corr_hl_vol = corr_hl_vol.rolling(window).mean()
        sign_signal = np.sign(corr_hl_vol - mean_corr_hl_vol)
        raw = raw_rsi * sign_signal
        rolling_mean = raw.rolling(window).mean()
        rolling_std = raw.rolling(window).std()
        signal = ((raw - rolling_mean) / rolling_std).clip(-1, 1)
        return -signal

    @staticmethod
    def alpha_quanta_randomizer_250_k(df, window=20):
        rsi = 100 - 100 / (1 + df['close'].rolling(5).apply(lambda x: pd.Series(x).pct_change().fillna(0).mean() / pd.Series(x).pct_change().fillna(0).mask(pd.Series(x).pct_change().fillna(0) < 0, 0).sum() / pd.Series(x).pct_change().fillna(0).mask(pd.Series(x).pct_change().fillna(0) > 0, 0).sum().clip(lower=1e-9), raw=False))
        ts_corr = (df['high'] - df['low']).rolling(5).corr(df['matchingVolume'])
        ts_mean = ts_corr.rolling(20).mean()
        raw = (50 - rsi) * np.sign(ts_corr - ts_mean)
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

