    @staticmethod
    def alpha_quanta_randomizer_250_r(df, window=20, quantile=0.05):
        rsi = 100 - 100 / (1 + df['close'].rolling(5).apply(lambda x: pd.Series(x).pct_change().fillna(0).mean() / pd.Series(x).pct_change().fillna(0).mask(pd.Series(x).pct_change().fillna(0) < 0, 0).sum() / pd.Series(x).pct_change().fillna(0).mask(pd.Series(x).pct_change().fillna(0) > 0, 0).sum().clip(lower=1e-9), raw=False))
        ts_corr = (df['high'] - df['low']).rolling(5).corr(df['matchingVolume'])
        ts_mean = ts_corr.rolling(20).mean()
        raw = (50 - rsi) * np.sign(ts_corr - ts_mean)
        low = raw.rolling(window).quantile(quantile)
        high = raw.rolling(window).quantile(1 - quantile)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        normalized = np.arctanh(((winsorized - low) / (high - low + 1e-9)) * 1.98 - 0.99)
        return normalized.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_251_rank(df, window=25):
        delta_close = df['close'].diff(3)
        std_close = df['close'].rolling(window).std()
        hl = df['high'] - df['low']
        hl_std = hl.rolling(3).std()
        hl_med = hl.rolling(window).median()
        raw = (delta_close / (std_close + 1e-9)) * (hl_std / (hl_med + 1e-9))
        normalized = (raw.rolling(2*window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

