    @staticmethod
    def alpha_quanta_randomizer_252_rank(df, window=50):
        close = df['close']
        high = df['high']
        low = df['low']
        delta = close.diff()
        gain = delta.clip(lower=0)
        loss = -delta.clip(upper=0)
        avg_gain = gain.rolling(window).mean()
        avg_loss = loss.rolling(window).mean()
        rs = avg_gain / avg_loss.replace(0, np.nan)
        rsi = 100 - (100 / (1 + rs))
        raw1 = (rsi - 50) / 20
        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = close.rolling(window).cov(days)
        var_x = days.rolling(window).var().replace(0, np.nan)
        if var_x.isna().all():
            beta = pd.Series(np.zeros(len(df)), index=df.index)
        else:
            beta = cov / var_x
        raw2 = 1 - beta.abs()
        range_ = high - low
        ts_mean_range = range_.rolling(window).mean()
        ts_std_close = close.rolling(window).std() + 1e-8
        raw3 = ts_mean_range / ts_std_close
        raw = raw1 * raw2 * raw3
        raw = raw.ffill().fillna(0)
        signal = (raw.rolling(2*window).rank(pct=True) * 2) - 1
        return signal

