        days = pd.Series(np.arange(len(df)), index=df.index)
        cov = close.rolling(window).cov(days)
        var_x = days.rolling(window).var().replace(0, np.nan)
        if var_x.isna().all():
            beta = pd.Series(np.zeros(len(df)), index=df.index)
        else:
            beta = cov / var_x
        raw2 = 1 - beta.abs()
        range_ = high - low
        ts_mean_range = range_.rolling(window).mean()
        ts_std_close = close.rolling(window).std() + 1e-8
        raw3 = ts_mean_range / ts_std_close
        raw = raw1 * raw2 * raw3
        raw = raw.ffill().fillna(0)
        signal = np.tanh(raw / raw.rolling(2*window).std())
        return signal

