    @staticmethod
    def alpha_quanta_randomizer_258_wf(df, window=40, factor=0.3):
        ret = df['close'].pct_change()
        vol_delta = df['matchingVolume'].diff(1) / (df['matchingVolume'] + 1e-8)
        corr = ret.rolling(window).corr(vol_delta)
        mean_ret = ret.rolling(window).mean()
        raw = corr * mean_ret
        low = raw.rolling(window).quantile(factor)
        high = raw.rolling(window).quantile(1 - factor)
        winsorized = raw.clip(lower=low, upper=high, axis=0)
        range_val = high - low
        denominator = range_val.replace(0, np.nan) + 1e-9
        normalized = np.arctanh(((winsorized - low) / denominator) * 1.98 - 0.99)
        signal = normalized.fillna(0)
        return signal

