    @staticmethod
    def alpha_quanta_randomizer_260_rank(df, window=100, sub_window=7):
        close = df['close']
        returns = close.pct_change()
        raw = returns.rolling(window).sum() / (close.rolling(sub_window).max() - close.rolling(sub_window).min() + 1)
        signal = raw * np.sign(returns.rolling(10).mean())
        # Trường hợp A: Rolling Rank
        normalizer = signal.rolling(window).rank(pct=True) * 2 - 1
        return -normalizer.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_260_tanh(df, window=100, sub_window=10):
        close = df['close']
