        signal = raw * np.sign(returns.rolling(10).mean())
        # Trường hợp C: Rolling Z-Score/Clip
        mean = signal.rolling(window).mean()
        std = signal.rolling(window).std().replace(0, np.nan)
        normalizer = ((signal - mean) / std).clip(-1, 1)
        return -normalizer.fillna(0)

