    @staticmethod
    def alpha_quanta_randomizer_263_k(df, window=100):
        close = df['close']
        delay_close = close.shift(1)
        raw_a = (df['open'] - delay_close).abs() / (close.rolling(window).std() + 1e-8)
        raw_a_ranked = raw_a.rolling(window).rank(pct=True)
        hi_lo = df['high'] - df['low']
        std_hi_lo = hi_lo.rolling(20).std()
        condition = hi_lo < std_hi_lo
        volume_adj = df['matchingVolume'].where(condition, 0)
        mean_volume_adj = volume_adj.rolling(20).mean()
        mean_volume = df['matchingVolume'].rolling(20).mean() + 1e-8
        raw_b_ranked = (mean_volume_adj / mean_volume).rolling(window).rank(pct=True)
        raw = raw_a_ranked * raw_b_ranked
        signal = (raw.rolling(window).rank(pct=True) * 2) - 1
        return signal.fillna(0)

