    @staticmethod
    def alpha_quanta_randomizer_264_rank(df, window=90):
        high = df['high']
        low = df['low']
        volume = df['matchingVolume']
        spread = high - low
        std10 = spread.rolling(window).std()
        vol_high = np.where(spread > std10, volume, 0)
        vol_high_series = pd.Series(vol_high, index=df.index)
        mean_vol_high = vol_high_series.rolling(window).mean()
        vol_low = np.where(spread < std10, volume, 0)
        vol_low_series = pd.Series(vol_low, index=df.index)
        mean_vol_low = vol_low_series.rolling(window).mean()
        ratio1 = mean_vol_high / (mean_vol_low + 1e-8)
        std20 = spread.rolling(20).std()
        vol_big = np.where(spread < std20, volume, 0)
        vol_big_series = pd.Series(vol_big, index=df.index)
        mean_vol_big = vol_big_series.rolling(20).mean()
        mean_vol_20 = volume.rolling(20).mean()
        ratio2 = mean_vol_big / (mean_vol_20 + 1e-8)
        rank_ratio2 = ratio2.rolling(window).rank(pct=True)
        raw = ratio1 * rank_ratio2
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

