        std10 = spread.rolling(window).std()
        vol_high = np.where(spread > std10, volume, 0)
        vol_high_series = pd.Series(vol_high, index=df.index)
        mean_vol_high = vol_high_series.rolling(window).mean()
        vol_low = np.where(spread < std10, volume, 0)
