    @staticmethod
    def alpha_quanta_randomizer_266_rank(df, window=100, window_rank=7):
        close = df['close']
        delta = close.diff()
        gain = delta.clip(lower=0).rolling(window).mean()
        loss = (-delta.clip(upper=0)).rolling(window).mean()
        rs = gain / loss.replace(0, np.nan)
        rsi = 100 - (100 / (1 + rs))
        rsi_signal = np.sign(rsi - 50)
        mid = close.rolling(window).mean()
        std = close.rolling(window).std()
        upper = mid + 2 * std
        lower = mid - 2 * std
        bb_raw = (close - mid) / (upper - lower + 1e-8)
        bb_std = bb_raw.rolling(window).std()
        bb_zscore = (bb_raw - bb_raw.rolling(window).mean()) / bb_std.replace(0, np.nan)
        raw = rsi_signal * bb_zscore
        signal = raw.rolling(window_rank).rank(pct=True) * 2 - 1
        return signal.fillna(0)

