        numerator = (slope_positive & vol_delta).rolling(window).sum()
        denominator = slope_positive.rolling(window).sum() + 1e-8
        raw = numerator / denominator
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized

