    @staticmethod
    def alpha_quanta_randomizer_271_rank(df, window=40):
        volume = df['matchingVolume']
        high = df['high']
        low = df['low']
        close = df['close']
        hl = high - low
        delay_close = close.shift(1)
        delay_volume = volume.shift(1)
        delay_hl = hl.shift(1)
        true_range = np.maximum(hl, np.maximum(np.abs(high - delay_close), np.abs(low - delay_close)))
        vol_mean = volume.rolling(window).mean() + 1e-8
        tr_mean = hl.rolling(window).mean() + 1e-8
        z_vol = (volume / vol_mean - volume.rolling(window).mean()) / volume.rolling(window).std()
        z_tr = (true_range / tr_mean - true_range.rolling(window).mean()) / true_range.rolling(window).std()
        z_delay_vol = (delay_volume / (volume + 1e-8) - (delay_volume / (volume + 1e-8)).rolling(window).mean()) / (delay_volume / (volume + 1e-8)).rolling(window).std()
        z_delay_hl = (delay_hl / (hl + 1e-8) - (delay_hl / (hl + 1e-8)).rolling(window).mean()) / (delay_hl / (hl + 1e-8)).rolling(window).std()
        raw = z_vol.fillna(0) + z_tr.fillna(0) - z_delay_vol.fillna(0) - z_delay_hl.fillna(0)
        result = (raw.rolling(window).rank(pct=True) * 2) - 1
        return result.fillna(0)

