        hilo_std = hilo.rolling(w).std().replace(0, np.nan)
        ts_zscore = (hilo - hilo_mean) / hilo_std
        prev_zscore = ts_zscore.shift(1)
        prev_close_low = (df['close'] - df['low']).shift(1)
        prev_high_close = (df['high'] - df['close']).shift(1)
        prev_hilo_eps = (df['high'] - df['low']).shift(1) + 1e-8
        prev_bw_ratio = (prev_close_low - prev_high_close) / prev_hilo_eps
        hilo_mean_20 = hilo.rolling(w).mean()
        raw = np.where((prev_zscore >= 1) & (prev_bw_ratio <= -0.5) & (hilo <= hilo_mean_20), prev_zscore, 0.0)
        raw_series = pd.Series(raw, index=df.index)
        match_cnt = (1 - raw_series.isna()).rolling(w).count()
        rank_val = (raw_series.rolling(w, min_periods=1).rank(pct=True) * 2) - 1
        result = rank_val.fillna(0).clip(-1, 1)
        return -result

