    @staticmethod
    def alpha_quanta_randomizer_277_rank(df, window_rank=10, window_vol=30):
        close = df['close']
        high = df['high']
        low = df['low']
        vol_60 = (high - low) / close.replace(0, np.nan)
        vol_60_mean = vol_60.rolling(window=window_rank).mean()
        raw_inv = 1 / (1 + vol_60_mean)
        term1 = raw_inv.rolling(window_rank).rank(pct=True) * 2 - 1
        ret = close / close.shift(1) - 1
        pos_ret = ret.clip(0, None)
        max_pos = pos_ret
        vol_20 = (high - low) / close.replace(0, np.nan)
        vol_20_mean = vol_20.rolling(window=window_vol).mean()
        term2 = max_pos / (vol_20_mean + 1e-8)
        raw_mid = term1 * term2
        cond1 = (close >= close.shift(1)).rolling(3).sum() == 3
        vol_3_mean = vol_20.rolling(3).mean()
        cond2 = vol_3_mean <= 0.8 * vol_20_mean
        signal_if = pd.Series(np.where(cond1 & cond2, raw_mid, 0.0), index=df.index)
        result = signal_if.rolling(window_rank).rank(pct=True) * 2 - 1
        return result.fillna(0)

