    @staticmethod
    def alpha_quanta_randomizer_277_wf(df, p1=0.1, window=90):
        close = df['close']
        high = df['high']
        low = df['low']
        vol = (high - low) / close.replace(0, np.nan)
        vol_mean = vol.rolling(window=window).mean()
        raw_inv = 1 / (1 + vol_mean)
        ret = close / close.shift(1) - 1
        pos_ret = ret.clip(0, None)
        max_pos = pos_ret
        vol_20_mean = vol.rolling(window=window).mean()
        term2 = max_pos / (vol_20_mean + 1e-8)
        raw_mid = raw_inv * term2
        cond1 = (close >= close.shift(1)).rolling(3).sum() == 3
        vol_3_mean = vol.rolling(3).mean()
        cond2 = vol_3_mean <= 0.8 * vol_20_mean
        signal_if = pd.Series(np.where(cond1 & cond2, raw_mid, 0.0), index=df.index)
        low_perc = signal_if.rolling(window).quantile(p1)
        high_perc = signal_if.rolling(window).quantile(1 - p1)
        winsorized = signal_if.clip(lower=low_perc, upper=high_perc, axis=0)
        norm_val = (winsorized - low_perc) / (high_perc - low_perc + 1e-9)
        result = np.arctanh(norm_val * 1.98 - 0.99)
        return result.fillna(0)

    @staticmethod
    def alpha_quanta_randomizer_278_rank(df, window=40, sub_window=3):
        close = df['close']
        high = df['high']
