        zscore = (returns - returns.rolling(window).mean()) / returns.rolling(window).std()
        zscore_max = zscore.clip(0, None)
        cond1 = (close >= close.shift(1)).rolling(sub_window).sum() == sub_window
        range_ratio = (high - low) / close
        cond2 = range_ratio.rolling(sub_window).mean() <= 0.75 * range_ratio.rolling(window).mean()
        signal = zscore_max * np.where(cond1 & cond2, 1, 0)
        signal = signal.ffill().fillna(0)
        normalized = (signal.rolling(window).rank(pct=True) * 2) - 1
        return normalized

