    @staticmethod
    def alpha_quanta_randomizer_280_rank(df, window=10):
        ret = df['close'].pct_change()
        std_60 = ret.rolling(window).std()
        hl = (df['high'] - df['low']) / (df['close'] + 1e-8)
        mean_hl_60 = hl.rolling(window).mean()
        mean_ret_5 = ret.rolling(5).mean()
        delta_mean_ret = mean_ret_5.diff(20)
        vol = df.get('matchingVolume', df.get('volume', 1))
        ret_vol_5 = (ret * vol).rolling(5).mean()
        raw = -std_60 - mean_hl_60 + delta_mean_ret + ret_vol_5
        rank = raw.rolling(window).rank(pct=True)
        signal = rank * 2 - 1
        signal = signal.replace([np.inf, -np.inf], np.nan).ffill().fillna(0)
        return signal

