    @staticmethod
    def alpha_quanta_randomizer_292_rank(df, window=90):
        sub_window = 5
        close = df['close']
        high = df['high']
        low = df['low']
        volume = df.get('matchingVolume', df.get('volume', 1))
        pct_change = close.pct_change(window)
        sign = np.sign(pct_change)
