        vol_gt_mean = volume > volume.rolling(window).mean()
        both_cond = (price_up & vol_gt_mean).astype(int)
        raw = both_cond.rolling(window).sum() / window
        normalized = (raw.rolling(window).rank(pct=True) * 2) - 1
        return normalized.fillna(0)

