    @staticmethod
    def alpha_quanta_randomizer_321_wf(df, window=10, quantile=0.1):
        data = df.copy()
        high_low = data['high'] - data['low']
        mean_hl = high_low.rolling(window, min_periods=1).mean()
        raw_1 = high_low / (mean_hl + 1e-8)
